INSERT INTO `lesson_translations` (`id`, `lesson_id`, `language_code`, `title`, `notes`, `audio_url`, `is_published`, `created_at`, `updated_at`) VALUES
(1, 1, 'te', 'మనుషులు మరియు ప్రయాణం', 'Podcast Title: German Telugu Lesson 1, Menschen und Reisen\r\n\r\nIntro music, soft and calm.\r\n\r\nNamaskaram friends. Welcome to our German learning podcast.\r\n\r\nఈ రోజు మనం German లో చాలా basic కానీ చాలా useful అయిన chapter నేర్చుకోబోతున్నాం. Chapter పేరు **Menschen und Reisen**. అంటే Telugu లో **మనుషులు మరియు ప్రయాణం**.\r\n\r\nఇది beginner level chapter. కానీ చాలా important. ఎందుకంటే Germany లో మనం బయటికి వెళ్ళినప్పుడు, station లో, airport లో, hotel లో, bus stop దగ్గర, information counter దగ్గర, appointment కి వెళ్ళినప్పుడు, basic German words చాలా అవసరం అవుతాయి.\r\n\r\nఈ lesson లో మనం నేర్చుకునేది:\r\nముందుగా announcements ఎలా వినాలి.\r\nతర్వాత మన పేరు ఎలా చెప్పాలి.\r\nఇతరుల పేరు ఎలా అడగాలి.\r\nNumbers 1 to 10.\r\nDaily travel words.\r\nGerman articles, అంటే der, die, das.\r\nచివరిగా singular and plural.\r\n\r\nSo relax. Slowly వినండి. Repeat చేయండి. German మొదట కష్టం అనిపిస్తుంది, కానీ step by step వెళ్తే చాలా easy అవుతుంది.\r\n\r\nLet’s start.\r\n\r\nముందుగా chapter theme చూద్దాం. **Menschen und Reisen**.\r\n\r\n**Menschen** అంటే people, మనుషులు.\r\n**Reisen** అంటే travel, ప్రయాణం.\r\n\r\nఅంటే ఈ chapter లో station లో, taxi లో, train లో, hotel దగ్గర, information counter దగ్గర జరిగే small conversations ఉంటాయి.\r\n\r\nImagine చేయండి. మీరు Berlin లో ఒక train station లో ఉన్నారు. Around you people are walking. కొంతమంది taxi కోసం చూస్తున్నారు. కొంతమంది train కోసం wait చేస్తున్నారు. ఇంకొంతమంది information counter దగ్గర అడుగుతున్నారు. Suddenly ఒక announcement వస్తుంది.\r\n\r\n**Frau Beier bitte zur Information.**\r\n\r\nదీనికి అర్థం: **Mrs. Beier, please come to the information desk.**\r\n\r\nఇక్కడ important words:\r\n\r\n**Frau** అంటే Mrs. లేదా Ms.\r\n**Herr** అంటే Mr.\r\n**bitte** అంటే please.\r\n**zur Information** అంటే information counter దగ్గరకు.\r\n\r\nఇప్పుడు ఇంకో sentence విందాం.\r\n\r\n**Herr Hans Meier bitte zur Information.**\r\n\r\nఅంటే: **Mr. Hans Meier, please come to the information counter.**\r\n\r\nFriends, Germany లో train station, airport, hospital, office లాంటి places లో announcements common. అందుకే మీ పేరు లేదా ఎవరి పేరు announce చేస్తే గుర్తుపట్టడం చాలా important.\r\n\r\nCommon mistake ఏంటంటే, beginner learners **Frau** and **Herr** confuse అవుతారు.\r\n\r\nSimple rule గుర్తుపెట్టుకోండి:\r\n\r\n**Frau** female కోసం.\r\n**Herr** male కోసం.\r\n\r\nExample:\r\n\r\n**Frau Soprana**\r\nMrs. Soprana.\r\n\r\n**Herr Meier**\r\nMr. Meier.\r\n\r\nఇంకో mistake, మనం full sentence అర్థం కావట్లేదని panic అవుతాం. కానీ అవసరం లేదు. First మీరు keywords పట్టుకోండి. Name వినండి. Frau లేదా Herr వినండి. Information వినండి. అంతే, meaning roughly అర్థమవుతుంది.\r\n\r\nఇప్పుడు second concept కి వెళ్దాం.\r\n\r\nమీరు information counter దగ్గరికి వెళ్లారు. అక్కడ మీరు మీ పేరు చెప్పాలి. German లో ఎలా చెప్తారు?\r\n\r\nVery simple.\r\n\r\n**Guten Tag. Mein Name ist Jeremiah.**\r\n\r\nఅంటే: Good day. My name is Jeremiah.\r\n\r\nఇక్కడ **Guten Tag** అంటే hello లేదా good day. Formal situation లో చాలా good phrase.\r\n\r\n**Mein Name ist...** అంటే my name is...\r\n\r\nExample:\r\n\r\n**Mein Name ist Peter.**\r\nనా పేరు Peter.\r\n\r\n**Mein Name ist Meier.**\r\nనా పేరు Meier.\r\n\r\nGerman లో name చెప్పడానికి ఇంకో common sentence ఉంది.\r\n\r\n**Ich heiße Jeremiah.**\r\n\r\nఅంటే: My name is Jeremiah.\r\n\r\nఇది beginner కి చాలా important sentence. Repeat చేయండి:\r\n\r\n**Ich heiße Jeremiah.**\r\n\r\nఇంకో way:\r\n\r\n**Ich bin Jeremiah.**\r\n\r\nఅంటే: I am Jeremiah.\r\n\r\nSo, name చెప్పడానికి three ways:\r\n\r\n**Mein Name ist Jeremiah.**\r\n**Ich heiße Jeremiah.**\r\n**Ich bin Jeremiah.**\r\n\r\nమూడు correct. కానీ beginner level లో **Mein Name ist...** and **Ich heiße...** చాలా useful.\r\n\r\nఇప్పుడు ఒక small scene imagine చేయండి.\r\n\r\nReceptionist: Guten Tag.\r\nYou: Guten Tag. Mein Name ist Jeremiah.\r\nReceptionist: Heißen Sie Jeremiah Elior?\r\nYou: Ja, ich bin Jeremiah Elior.\r\n\r\nఇక్కడ **Ja** అంటే yes.\r\n\r\nఇప్పుడు **Vorname** and **Nachname** నేర్చుకుందాం.\r\n\r\n**Vorname** అంటే first name.\r\n**Nachname** అంటే last name.\r\n\r\nExample:\r\n\r\nJeremiah Elior అనే పేరు తీసుకుంటే:\r\n\r\n**Mein Vorname ist Jeremiah.**\r\nనా first name Jeremiah.\r\n\r\n**Mein Nachname ist Elior.**\r\nనా last name Elior.\r\n\r\nCommon mistake: చాలామంది German forms fill చేస్తప్పుడు Vorname and Nachname confuse అవుతారు. Germany లో forms లో ఇవి చాలా common.\r\n\r\nVorname = first name.\r\nNachname = family name or last name.\r\n\r\nఇది బాగా గుర్తుపెట్టుకోండి.\r\n\r\nఇప్పుడు third concept. ఎదుటి వ్యక్తి పేరు ఎలా అడగాలి?\r\n\r\nGerman లో polite way:\r\n\r\n**Wie heißen Sie, bitte?**\r\n\r\nఅంటే: What is your name, please?\r\n\r\nఇక్కడ **Sie** అంటే polite you. Telugu లో “మీరు” లాంటిది.\r\n\r\nRepeat:\r\n\r\n**Wie heißen Sie, bitte?**\r\n\r\nAnswer:\r\n\r\n**Ich heiße Jeremiah.**\r\n\r\nలేదా:\r\n\r\n**Mein Name ist Jeremiah.**\r\n\r\nఇంకో question:\r\n\r\n**Heißen Sie Hans Meier?**\r\n\r\nఅంటే: Are you Hans Meier?\r\n\r\nAnswer:\r\n\r\n**Ja, ich bin Hans Meier.**\r\n\r\nలేదా:\r\n\r\n**Nein, mein Vorname ist Peter.**\r\n\r\nఅంటే: No, my first name is Peter.\r\n\r\nఇక్కడ **Nein** అంటే no.\r\n\r\nSo now మనకు small conversation ready అయింది.\r\n\r\nA: Guten Tag. Wie heißen Sie, bitte?\r\nB: Guten Tag. Mein Name ist Meier.\r\nA: Heißen Sie Hans Meier?\r\nB: Nein, mein Vorname ist Peter.\r\n\r\nఇప్పుడు ఈ conversation ఎందుకు important అంటే, real life లో office, doctor appointment, school, Kita, Bürgeramt, job interview, hotel check-in, everywhere you need this.\r\n\r\nCommon mistake ఏంటంటే, **Wie heißen Sie?** అన్నప్పుడు కొంతమంది **Ich bin gut** అంటారు. అది wrong. **Ich bin gut** అంటే “I am good.” కానీ question name గురించి.\r\n\r\nCorrect answer:\r\n\r\n**Ich heiße Jeremiah.**\r\n\r\nఇప్పుడు polite and informal గురించి మాట్లాడుకుందాం.\r\n\r\nGerman లో “you” కి రెండు common forms ఉన్నాయి.\r\n\r\n**Sie** and **du**.\r\n\r\n**Sie** అంటే formal you. Unknown adults, officers, teachers, receptionists, doctors, managers, official places లో use చేయాలి.\r\n\r\n**du** అంటే informal you. Friends, family, children, close people తో use చేస్తారు.\r\n\r\nExample:\r\n\r\nFormal:\r\n**Wie heißen Sie?**\r\n\r\nInformal:\r\n**Wie heißt du?**\r\n\r\nChapter లో ఒక sentence ఉంది:\r\n\r\n**Hallo, ich heiße Claudia. Und du?**\r\n\r\nఅంటే: Hi, my name is Claudia. And you?\r\n\r\nఇది friends లేదా kids మధ్య conversation లాగా ఉంటుంది.\r\n\r\nBut police officer లేదా receptionist తో **Und du?** అనకూడదు. అక్కడ **Und Sie?** అని politeగా అడగాలి.\r\n\r\nఇది చాలా important cultural point. German లో respect చూపించడానికి **Sie** చాలా useful.\r\n\r\nఇప్పుడు numbers కి వెళ్దాం.\r\n\r\nNumbers 1 to 10.\r\n\r\nListen and repeat.\r\n\r\n1, **eins**\r\n2, **zwei**\r\n3, **drei**\r\n4, **vier**\r\n5, **fünf**\r\n6, **sechs**\r\n7, **sieben**\r\n8, **acht**\r\n9, **neun**\r\n10, **zehn**\r\n\r\nఇప్పుడు slowly:\r\n\r\n**eins**\r\n**zwei**\r\n**drei**\r\n**vier**\r\n**fünf**\r\n**sechs**\r\n**sieben**\r\n**acht**\r\n**neun**\r\n**zehn**\r\n\r\nNumbers ఎందుకు important? Very simple. Germany లో మీరు bus number చూడాలి, platform number చూడాలి, appointment token number వినాలి, phone number చెప్పాలి, room number చెప్పాలి.\r\n\r\nExample:\r\n\r\nBus 7 = **Bus sieben**\r\nRoom 8 = **Zimmer acht**\r\nPlatform 3 = **Gleis drei**\r\n\r\nBeginner mistake pronunciation లో ఉంటుంది.\r\n\r\n**zwei** ని “జ్వై” అని కాకుండా “త్స్వై” లాగా pronounce చేయాలి.\r\n\r\n**sieben** ని “సీబెన్” లాగా pronounce చేయాలి.\r\n\r\n**acht** లో sound కొంచెం strong. English “act” లాగా కాదు. German sound కొంచెం throat నుండి వస్తుంది.\r\n\r\nBut don’t worry. First day నుంచే perfect pronunciation అవసరం లేదు. But listening and repeating daily important.\r\n\r\nఇప్పుడు next powerful sentence:\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nఇది language learning లో super useful sentence.\r\n\r\nMeaning: **దీన్ని German లో ఏమంటారు?**\r\n\r\nమీరు ఏ object అయినా చూపించి ఈ sentence అడగొచ్చు.\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nExample:\r\n\r\nTrain చూపించి అడిగారు:\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nAnswer:\r\n\r\n**Das ist der Zug.**\r\n\r\nఅంటే: ఇది train.\r\n\r\nTaxi చూపించి అడిగారు:\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nAnswer:\r\n\r\n**Das ist das Taxi.**\r\n\r\nHotel చూపించి:\r\n\r\n**Das ist das Hotel.**\r\n\r\nNewspaper చూపించి:\r\n\r\n**Das ist die Zeitung.**\r\n\r\nఇక్కడ మనం vocabulary నేర్చుకుంటున్నాం.\r\n\r\nChapter లో ఉన్న words చూద్దాం.\r\n\r\n**der Zug** = train\r\n**das Taxi** = taxi\r\n**das Hotel** = hotel\r\n**die Bank** = bank\r\n**das Telefon** = telephone\r\n**die Zeitung** = newspaper\r\n**der Geldautomat** = ATM\r\n**der Bus** = bus\r\n**die Uhr** = clock or watch\r\n\r\nఇవి travel and city life లో very common words.\r\n\r\nLet’s repeat with articles.\r\n\r\n**der Zug**\r\n**das Taxi**\r\n**das Hotel**\r\n**die Bank**\r\n**das Telefon**\r\n**die Zeitung**\r\n**der Geldautomat**\r\n**der Bus**\r\n**die Uhr**\r\n\r\nఇప్పుడు articles గురించి మాట్లాడుకుందాం. German లో nouns కి articles ఉంటాయి.\r\n\r\nEnglish లో mostly “the” ఒక్కటే ఉంటుంది. But German లో మూడు common definite articles ఉన్నాయి:\r\n\r\n**der**\r\n**die**\r\n**das**\r\n\r\n**der** masculine.\r\n**die** feminine.\r\n**das** neuter.\r\n\r\nకానీ beginner గా మీరు ఇప్పుడే masculine, feminine, neuter logic లో ఎక్కువగా పడకండి. Best method ఏంటంటే, word ని articleతో కలిపి నేర్చుకోండి.\r\n\r\nTaxi అని కాదు, **das Taxi** అని నేర్చుకోండి.\r\nZug అని కాదు, **der Zug** అని నేర్చుకోండి.\r\nZeitung అని కాదు, **die Zeitung** అని నేర్చుకోండి.\r\n\r\nఎందుకు ఇది important? Later German grammar మొత్తం article మీద depend అవుతుంది. Sentence లో changes article నుంచే start అవుతాయి.\r\n\r\nExample:\r\n\r\n**der Zug**\r\nthe train.\r\n\r\n**die Bank**\r\nthe bank.\r\n\r\n**das Hotel**\r\nthe hotel.\r\n\r\nCommon mistake: noun మాత్రమే గుర్తుపెట్టుకోవడం.\r\nFor example, “Taxi” గుర్తుంది. But article తెలియదు. Then later sentence చేయలేరు.\r\n\r\nCorrect learning style:\r\n\r\n**das Taxi**\r\n**der Bus**\r\n**die Uhr**\r\n\r\nఇలా articleతో repeat చేయాలి.\r\n\r\nఇప్పుడు మనం known words గురించి మాట్లాడుకుందాం.\r\n\r\nGerman లో కొన్ని words మనకు already familiar. Like:\r\n\r\n**Taxi**\r\n**Hotel**\r\n**Bank**\r\n**Telefon**\r\n**Zoo**\r\n**Zentrum**\r\n\r\nఇవి చూసినప్పుడు మనం “అరే, ఇవి నాకు already తెలుసు” అనుకోవాలి. That gives confidence.\r\n\r\nGerman completely new language కాదు. మీరు daily life లో already కొన్ని German words చూసి ఉంటారు.\r\n\r\nBut again, article గుర్తుపెట్టుకోవాలి.\r\n\r\n**das Taxi**\r\n**das Hotel**\r\n**die Bank**\r\n**das Telefon**\r\n\r\nఇప్పుడు chapter లో station scene ఉంది, **Menschen am Bahnhof**. అంటే station లో ఉన్న people.\r\n\r\nLet’s learn people words.\r\n\r\n**der Reporter** = reporter\r\n**die Sängerin** = female singer\r\n**der Tourist** = male tourist\r\n**die Touristin** = female tourist\r\n**das Mädchen** = girl\r\n**der Junge** = boy\r\n**die Polizistin** = female police officer\r\n**die Verkäuferin** = saleswoman\r\n**das Baby** = baby\r\n**die Zwillinge** = twins\r\n\r\nఇక్కడ interesting thing చూడండి. Male tourist = **der Tourist**. Female tourist = **die Touristin**.\r\n\r\nGerman లో many professions or people words లో female form కి **-in** add అవుతుంది.\r\n\r\n**der Reporter** male reporter.\r\n**die Reporterin** female reporter.\r\n\r\n**der Verkäufer** male seller.\r\n**die Verkäuferin** female seller.\r\n\r\nఇప్పుడు small dialogues చూద్దాం.\r\n\r\n**Guten Tag, Frau Soprana. Herzlich willkommen.**\r\n\r\nMeaning: Good day, Mrs. Soprana. Warm welcome.\r\n\r\n**Danke für die Blumen.**\r\n\r\nMeaning: Thank you for the flowers.\r\n\r\n**Auf Wiedersehen. Gute Reise.**\r\n\r\nMeaning: Goodbye. Have a good journey.\r\n\r\n**Hallo, ich heiße Claudia. Und du?**\r\n\r\nMeaning: Hi, my name is Claudia. And you?\r\n\r\n**Halt! Wie heißen Sie?**\r\n\r\nMeaning: Stop! What is your name?\r\n\r\n**Oh! Verzeihung!**\r\n\r\nMeaning: Oh! Sorry. Or excuse me.\r\n\r\nఇవి small sentences అయినా, real life లో చాలా useful.\r\n\r\n**Auf Wiedersehen** is formal goodbye.\r\n**Tschüs** is casual goodbye.\r\n**Verzeihung** means sorry or excuse me.\r\n\r\nExample:\r\n\r\nమీరు ఎవరికైనా accidentally touch అయ్యారు.\r\n\r\nYou say:\r\n\r\n**Oh! Verzeihung!**\r\n\r\nమీరు journey కి వెళ్తున్న friend కి చెప్తారు:\r\n\r\n**Gute Reise!**\r\n\r\nఅంటే have a good journey.\r\n\r\nఇప్పుడు last concept, singular and plural.\r\n\r\nSingular అంటే ఒకటి.\r\nPlural అంటే ఒకటి కంటే ఎక్కువ.\r\n\r\nGerman లో plural forms different ఉంటాయి. English లాగా always “s” add చేయడం కాదు.\r\n\r\nExamples:\r\n\r\n**das Telefon**\r\none telephone.\r\n\r\nPlural:\r\n\r\n**die Telefone**\r\ntelephones.\r\n\r\n**das Taxi**\r\none taxi.\r\n\r\nPlural:\r\n\r\n**die Taxis**\r\ntaxis.\r\n\r\n**das Hotel**\r\none hotel.\r\n\r\nPlural:\r\n\r\n**die Hotels**\r\nhotels.\r\n\r\n**der Geldautomat**\r\none ATM.\r\n\r\nPlural:\r\n\r\n**die Geldautomaten**\r\nATMs.\r\n\r\n**die Blume**\r\none flower.\r\n\r\nPlural:\r\n\r\n**die Blumen**\r\nflowers.\r\n\r\n**der Zwilling**\r\none twin.\r\n\r\nPlural:\r\n\r\n**die Zwillinge**\r\ntwins.\r\n\r\nImportant beginner rule:\r\n\r\nPlural nouns usually use **die** as article.\r\n\r\nSingular లో der, die, das రావచ్చు.\r\nPlural లో usually **die**.\r\n\r\nExample:\r\n\r\n**das Taxi** becomes **die Taxis**.\r\n**das Hotel** becomes **die Hotels**.\r\n**der Geldautomat** becomes **die Geldautomaten**.\r\n\r\nCommon mistake:\r\n\r\n**das Taxis** అని చెప్పడం wrong. Correct: **die Taxis**.\r\n\r\n**der Geldautomaten** wrong. Correct plural: **die Geldautomaten**.\r\n\r\nఇప్పుడు మనం మొత్తం chapter connect చేద్దాం.\r\n\r\nFirst, మీరు station లో ఉన్నారు. Announcement విన్నారు:\r\n\r\n**Herr Meier bitte zur Information.**\r\n\r\nThen మీరు information counter దగ్గరకు వెళ్తారు:\r\n\r\n**Guten Tag. Mein Name ist Meier.**\r\n\r\nReceptionist అడుగుతాడు:\r\n\r\n**Heißen Sie Hans Meier?**\r\n\r\nమీరు అంటారు:\r\n\r\n**Nein, mein Vorname ist Peter.**\r\n\r\nతర్వాత మీరు train గురించి అడుగుతారు:\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nSomeone says:\r\n\r\n**Das ist der Zug.**\r\n\r\nమీరు bus number చూస్తారు:\r\n\r\n**Bus sieben.**\r\n\r\nతర్వాత hotel కి వెళ్తారు:\r\n\r\n**Das Hotel.**\r\n\r\nమీరు goodbye చెప్తారు:\r\n\r\n**Auf Wiedersehen. Gute Reise.**\r\n\r\nSee, ఈ small words తోనే ఒక complete travel situation build అవుతుంది.\r\n\r\nఇప్పుడు chapter summary.\r\n\r\nఈ lesson లో మనం నేర్చుకున్నవి:\r\n\r\n**Frau** means Mrs. or Ms.\r\n**Herr** means Mr.\r\n**bitte** means please.\r\n**zur Information** means to the information desk.\r\n\r\nName చెప్పడం:\r\n\r\n**Mein Name ist...**\r\n**Ich heiße...**\r\n**Ich bin...**\r\n\r\nName అడగడం:\r\n\r\n**Wie heißen Sie, bitte?**\r\n\r\nFormal you:\r\n\r\n**Sie**\r\n\r\nInformal you:\r\n\r\n**du**\r\n\r\nNumbers 1 to 10:\r\n\r\n**eins, zwei, drei, vier, fünf, sechs, sieben, acht, neun, zehn**\r\n\r\nObject name అడగడం:\r\n\r\n**Wie heißt das auf Deutsch?**\r\n\r\nTravel words:\r\n\r\n**der Zug, das Taxi, das Hotel, die Bank, das Telefon, die Zeitung, der Geldautomat, der Bus, die Uhr**\r\n\r\nArticles:\r\n\r\n**der, die, das**\r\n\r\nPlural:\r\n\r\n**das Taxi** becomes **die Taxis**\r\n**das Hotel** becomes **die Hotels**\r\n**die Blume** becomes **die Blumen**\r\n\r\nఇప్పుడు practical analogy తో ముగిద్దాం.\r\n\r\nGerman learning ఒక train journey లాంటిది.\r\n\r\nFirst station: greetings.\r\nSecond station: name introduction.\r\nThird station: numbers.\r\nFourth station: daily words.\r\nFifth station: articles.\r\nSixth station: singular and plural.\r\n\r\nమీరు ఒక్కసారిగా final destination కి వెళ్లలేరు. ప్రతి station దాటాలి. ఈ chapter first few stations. Strongగా నేర్చుకుంటే next German journey easy అవుతుంది.\r\n\r\nఇప్పుడు quick quiz.\r\n\r\nQuestion 1: **Guten Tag** అంటే ఏమిటి?\r\n\r\nQuestion 2: **Mein Name ist Jeremiah** అంటే ఏమిటి?\r\n\r\nQuestion 3: German లో politeగా “మీ పేరు ఏమిటి?” ఎలా అడుగుతారు?\r\n\r\nQuestion 4: **Frau** and **Herr** meanings ఏమిటి?\r\n\r\nQuestion 5: German numbers 1 to 5 చెప్పండి.\r\n\r\nQuestion 6: **Wie heißt das auf Deutsch?** meaning ఏమిటి?\r\n\r\nQuestion 7: Correct article ఏది: Taxi కి der, die, లేదా das?\r\n\r\nQuestion 8: **der Zug** అంటే ఏమిటి?\r\n\r\nQuestion 9: **das Hotel** plural ఏమిటి?\r\n\r\nQuestion 10: Unknown adult తో మాట్లాడేటప్పుడు **du** వాడాలా, **Sie** వాడాలా?\r\n\r\nAnswers:\r\n\r\n1. Good day or hello.\r\n2. My name is Jeremiah.\r\n3. Wie heißen Sie, bitte?\r\n4. Frau means Mrs. or Ms. Herr means Mr.\r\n5. eins, zwei, drei, vier, fünf.\r\n6. What is this called in German?\r\n7. das Taxi.\r\n8. the train.\r\n9. die Hotels.\r\n10. Sie.\r\n\r\nOutro:\r\n\r\nFriends, ఇదే మన first German Telugu podcast lesson. ఈ lesson ని ఒక్కసారి వినడం సరిపోదు. Daily 2 or 3 times repeat చేయండి. Especially sentences repeat చేయండి.\r\n\r\nGuten Tag.\r\nMein Name ist...\r\nWie heißen Sie?\r\nWie heißt das auf Deutsch?\r\nAuf Wiedersehen. Gute Reise.\r\n\r\nLanguage speaking ద్వారా వస్తుంది. కాబట్టి వినండి, repeat చేయండి, small sentences daily life లో use చేయండి.\r\n\r\nDanke schön. Auf Wiedersehen.', 'https://silver-llama-257051.hostingersite.com/uploads/audio/1781100518-a1-chapter1.m4a', 1, '2026-06-21 23:44:29', '2026-06-21 23:44:29'),
(2, 2, 'te', '', 'Podcast Title: German Telugu Lesson 2, Fokus Lesen\r\n\r\nIntro music, soft and calm.\r\n\r\nNamaskaram friends. Welcome back to our German learning podcast.\r\n\r\nఈ రోజు మనం German Lesson 2 నేర్చుకోబోతున్నాం. ఈ lesson పేరు **Fokus Lesen**. అంటే **Reading focus**. తెలుగులో చెప్పాలంటే, German చదవడం మీద focus చేసే lesson.\r\n\r\nLesson 1 లో మనం station, travel, names, greetings, numbers, articles, singular and plural నేర్చుకున్నాం. ఈ lesson 2 లో అదే base మీద ఇంకొంచెం ముందుకు వెళ్తాం.\r\n\r\nఈ రోజు మనం నేర్చుకునేది:\r\n\r\nPeople గురించి చిన్న sentences చదవడం.\r\n**ein** and **eine** meaning.\r\n**er, sie, es** pronouns.\r\nBasic verbs like kommt, geht, lacht, weint, winkt.\r\n“I” sentences, అంటే **Ich heiße, Ich wohne, Ich arbeite**.\r\n“You” questions, అంటే **Wie heißt du? Wo wohnst du? Was machst du?**\r\nచివరిగా ఒక simple German letter చదువుతాం.\r\n\r\nSo relax. Slowly వినండి. Repeat చేయండి. ఈ lesson German reading confidence build చేయడానికి చాలా useful.\r\n\r\nLet’s start.\r\n\r\nముందుగా page లో ఒక big station picture ఉంది. ఇది **Hauptbahnhof**. అంటే main railway station.\r\n\r\n**Hauptbahnhof** అంటే main train station.\r\n\r\nఈ picture లో చాలా German words కనిపిస్తున్నాయి:\r\n\r\n**Geldautomat**\r\n**Zeitungen**\r\n**Blumen**\r\n**Filme**\r\n**Geschenke**\r\n**Gleis**\r\n**Information**\r\n**Hotel**\r\n**Telefon**\r\n**Taxi**\r\n**Toilette**\r\n\r\nఇవి real life లో Germany station లో మీరు చూసే words.\r\n\r\nLesson 1 లో మనం already కొన్ని words నేర్చుకున్నాం:\r\n\r\n**das Taxi**\r\n**das Hotel**\r\n**das Telefon**\r\n**die Zeitung**\r\n**der Geldautomat**\r\n**der Zug**\r\n\r\nLesson 2 లో అదే words real scene లో కనిపిస్తున్నాయి. అంటే ఇప్పుడు vocabulary separate గా కాదు, real picture లో చూస్తున్నాం. ఇది reading skill కి first step.\r\n\r\nImportant point:\r\n\r\nGerman చదవడం అంటే ప్రతి word perfectగా translate చేయడం కాదు. First, familiar words identify చేయాలి. Then sentence meaning guess చేయాలి.\r\n\r\nExample:\r\n\r\nమీరు station లో **Information** word చూస్తే, అది information counter అని అర్థం.\r\n**Taxi** word చూస్తే taxi stand అని అర్థం.\r\n**Toilette** word చూస్తే restroom అని అర్థం.\r\n**Gleis** అంటే platform or track.\r\n\r\nCommon mistake ఏమిటంటే, German sentence లో unknown word చూసిన వెంటనే “నాకు అర్థం కావడం లేదు” అని stop అవ్వడం. అలా చేయకండి. తెలిసిన words పట్టుకోండి. Context చూడండి. Picture చూడండి. Meaning slowly వస్తుంది.\r\n\r\nఇప్పుడు first main reading concept కి వెళ్దాం.\r\n\r\nTitle:\r\n\r\n**Ein Verkäufer, eine Reporterin, ein Baby**\r\n\r\nఇక్కడ మూడు important words ఉన్నాయి:\r\n\r\n**ein**\r\n**eine**\r\n**ein**\r\n\r\nఇవి English లో **a** or **an** లాంటివి.\r\n\r\n**ein Verkäufer** అంటే a salesman.\r\n**eine Reporterin** అంటే a female reporter.\r\n**ein Baby** అంటే a baby.\r\n\r\nఇక్కడ ఎందుకు **ein** ఒకసారి, **eine** ఒకసారి వస్తుంది?\r\n\r\nBecause German nouns కి gender ఉంటుంది.\r\n\r\n**der Verkäufer** becomes **ein Verkäufer**.\r\n**die Reporterin** becomes **eine Reporterin**.\r\n**das Baby** becomes **ein Baby**.\r\n\r\nSimple beginner rule:\r\n\r\n**der** words usually take **ein**.\r\n**die** words take **eine**.\r\n**das** words take **ein**.\r\n\r\nExamples:\r\n\r\n**der Mann** becomes **ein Mann**.\r\nA man.\r\n\r\n**die Frau** becomes **eine Frau**.\r\nA woman.\r\n\r\n**das Mädchen** becomes **ein Mädchen**.\r\nA girl.\r\n\r\nVery important, **Mädchen** means girl, but article is **das**. So it becomes **ein Mädchen**. German లో article always natural gender మీద depend అవ్వదు. Word grammar మీద depend అవుతుంది.\r\n\r\nCommon mistake:\r\n\r\nPeople think girl female కాబట్టి **die Mädchen** singular అనుకుంటారు. But correct singular is:\r\n\r\n**das Mädchen**\r\n**ein Mädchen**\r\n\r\nPlural is:\r\n\r\n**die Mädchen**\r\n\r\nSo German లో word తో article కూడా కలిపి నేర్చుకోవాలి. Lesson 1 లో ఇదే నేర్చుకున్నాం. ఇప్పుడు **der, die, das** నుండి **ein, eine, ein** కి వస్తున్నాం.\r\n\r\nNow let’s learn the people sentences.\r\n\r\n**Das ist ein Verkäufer.**\r\nఅంటే: This is a salesman.\r\n\r\n**Er wohnt in Berlin.**\r\nఅంటే: He lives in Berlin.\r\n\r\nఇక్కడ **er** అంటే he.\r\n\r\nSo:\r\n\r\n**ein Verkäufer**\r\n**er wohnt**\r\n\r\nThe seller is male, so we use **er**.\r\n\r\nNext:\r\n\r\n**Das ist eine Reporterin.**\r\nThis is a female reporter.\r\n\r\n**Sie macht ein Interview.**\r\nShe does an interview.\r\n\r\nఇక్కడ **sie** అంటే she.\r\n\r\nNext:\r\n\r\n**Das ist ein Baby.**\r\nThis is a baby.\r\n\r\n**Es weint.**\r\nIt cries.\r\n\r\nఇక్కడ **es** అంటే it.\r\n\r\nFor baby, German uses **das Baby**, so pronoun is **es**.\r\n\r\nThis is very important concept:\r\n\r\n**der Mann** becomes **er**.\r\n**die Frau** becomes **sie**.\r\n**das Baby** becomes **es**.\r\n**das Mädchen** becomes **es**.\r\n\r\nLet’s repeat:\r\n\r\n**der Mann, er**\r\n**die Frau, sie**\r\n**das Baby, es**\r\n**das Mädchen, es**\r\n\r\nఇది English/Telugu speakers కి confusing అవుతుంది. Telugu లో girl అంటే “ఆమె” అని అనిపిస్తుంది. But German grammar లో **das Mädchen** కాబట్టి **es** వాడతారు.\r\n\r\nCommon mistake:\r\n\r\n**Das Mädchen lacht. Sie lacht.** అని beginner చెప్తారు. Daily spoken German లో sometimes people use natural gender, but grammar beginner level లో correct answer:\r\n\r\n**Das Mädchen lacht. Es lacht.**\r\n\r\nఇప్పుడు plural చూద్దాం.\r\n\r\n**Das sind Fußballfans.**\r\nThese are football fans.\r\n\r\n**Sie winken.**\r\nThey wave.\r\n\r\nఇక్కడ **sie** అంటే they కూడా అవుతుంది. Lowercase **sie** can mean she or they depending on sentence.\r\n\r\nExample:\r\n\r\n**Sie macht ein Interview.**\r\nShe does an interview.\r\n\r\n**Sie winken.**\r\nThey wave.\r\n\r\nHow to identify? Verb చూస్తే తెలుస్తుంది.\r\n\r\n**macht** singular. So **sie** = she.\r\n**winken** plural. So **sie** = they.\r\n\r\nThis is a big German reading trick. Pronoun మాత్రమే చూడకండి, verb కూడా చూడండి.\r\n\r\nNow verbs.\r\n\r\nThis lesson gives many simple action verbs:\r\n\r\n**kommen** = to come\r\n**gehen** = to go\r\n**lachen** = to laugh\r\n**weinen** = to cry\r\n**winken** = to wave\r\n**singen** = to sing\r\n**wohnen** = to live\r\n**heißen** = to be called\r\n**arbeiten** = to work\r\n**hören** = to hear or listen\r\n**spielen** = to play\r\n**warten** = to wait\r\n**schreiben** = to write\r\n**lieben** = to love\r\n**träumen** = to dream\r\n\r\nGerman verbs change based on person.\r\n\r\nBut don’t worry. Today we only learn beginner patterns.\r\n\r\nFor **er, sie, es**, many verbs end with **-t**.\r\n\r\nExamples:\r\n\r\n**Er wohnt.**\r\nHe lives.\r\n\r\n**Sie macht.**\r\nShe does.\r\n\r\n**Es weint.**\r\nIt cries.\r\n\r\n**Ein Mädchen lacht.**\r\nA girl laughs.\r\n\r\n**Eine Frau singt.**\r\nA woman sings.\r\n\r\n**Ein Mann kommt.**\r\nA man comes.\r\n\r\nSo beginner pattern:\r\n\r\n**er, sie, es** plus verb often ends in **-t**.\r\n\r\nExamples:\r\n\r\n**er kommt**\r\nhe comes.\r\n\r\n**sie geht**\r\nshe goes.\r\n\r\n**es lacht**\r\nit laughs.\r\n\r\n**er winkt**\r\nhe waves.\r\n\r\nCommon mistake:\r\n\r\nUsing base verb directly.\r\n\r\nWrong: **Er kommen.**\r\nCorrect: **Er kommt.**\r\n\r\nWrong: **Sie gehen.** when meaning one woman goes.\r\nCorrect: **Sie geht.**\r\n\r\nBut for plural, **sie kommen** is correct.\r\n\r\nExample:\r\n\r\n**Menschen kommen und gehen.**\r\nPeople come and go.\r\n\r\nHere **Menschen** is plural. So verb is **kommen** and **gehen**.\r\n\r\nNow let’s read small examples from the lesson style.\r\n\r\n**Ein Mann singt. Er ist glücklich.**\r\nA man sings. He is happy.\r\n\r\nBreakdown:\r\n\r\n**Ein Mann** = a man.\r\n**singt** = sings.\r\n**Er** = he.\r\n**ist glücklich** = is happy.\r\n\r\nFull meaning:\r\n\r\nఒక మనిషి పాట పాడుతున్నాడు. అతను సంతోషంగా ఉన్నాడు.\r\n\r\nNext:\r\n\r\n**Eine Frau geht. Sie ist allein.**\r\nA woman goes. She is alone.\r\n\r\n**Eine Frau** = a woman.\r\n**geht** = goes.\r\n**Sie** = she.\r\n**allein** = alone.\r\n\r\nNext:\r\n\r\n**Ein Mädchen kommt. Es singt. Es heißt Carmen.**\r\nA girl comes. She sings. Her name is Carmen.\r\n\r\nLiterally German grammar:\r\n\r\nA girl comes. It sings. It is called Carmen.\r\n\r\nBut in Telugu meaning:\r\n\r\nఒక అమ్మాయి వస్తుంది. ఆమె పాడుతుంది. ఆమె పేరు Carmen.\r\n\r\nHere grammar says **es**, because **das Mädchen**.\r\n\r\nNext:\r\n\r\n**Menschen kommen und gehen. Sie sind Touristen. Sie winken.**\r\nPeople come and go. They are tourists. They wave.\r\n\r\nఇక్కడ **sie** means they.\r\n\r\nNow let’s move to the beautiful station text.\r\n\r\nTitle:\r\n\r\n**Ein Bahnhof**\r\n\r\nఅంటే: A train station.\r\n\r\nThis text is like a small poem.\r\n\r\nListen:\r\n\r\n**Menschen kommen und gehen, lachen und weinen.**\r\n\r\nMeaning:\r\n\r\nPeople come and go, laugh and cry.\r\n\r\nVery nice sentence. Station లో ఎప్పుడూ ఇదే జరుగుతుంది. Some people arrive, some people leave. Some people are happy, some people are sad.\r\n\r\nNext:\r\n\r\n**Ein Zug kommt.**\r\nA train comes.\r\n\r\n**Touristen. Sie reisen. Sie winken.**\r\nTourists. They travel. They wave.\r\n\r\n**Ein Mädchen. Es lacht.**\r\nA girl. She laughs.\r\n\r\n**Eine Frau. Ein Mann.**\r\nA woman. A man.\r\n\r\n**Er sagt: Auf Wiedersehen.**\r\nHe says: Goodbye.\r\n\r\n**Ein Kuss.**\r\nA kiss.\r\n\r\n**Aber sie weint.**\r\nBut she cries.\r\n\r\nఇక్కడ **aber** అంటే but.\r\n\r\nThis text is not just grammar. It shows emotion. Station లో goodbye scenes ఉంటాయి. Someone leaves. Someone cries. Someone waves. Someone says goodbye.\r\n\r\nNext:\r\n\r\n**Wer ist der Mann?**\r\nWho is the man?\r\n\r\n**Wie heißt die Frau?**\r\nWhat is the woman’s name?\r\n\r\n**Wo wohnt er?**\r\nWhere does he live?\r\n\r\n**Wo wohnt sie?**\r\nWhere does she live?\r\n\r\nNow we learn question words:\r\n\r\n**Wer** = who\r\n**Wie** = how or what, depending on sentence\r\n**Wo** = where\r\n**Wann** = when\r\n**Was** = what\r\n\r\nExamples:\r\n\r\n**Wer ist der Mann?**\r\nWho is the man?\r\n\r\n**Wie heißt die Frau?**\r\nWhat is the woman’s name?\r\n\r\n**Wo wohnt er?**\r\nWhere does he live?\r\n\r\n**Wann kommst du?**\r\nWhen are you coming?\r\n\r\n**Was machst du?**\r\nWhat are you doing?\r\n\r\nCommon mistake:\r\n\r\nStudents confuse **Wo** and **Wer**.\r\n\r\n**Wo** = where. Place.\r\n**Wer** = who. Person.\r\n\r\nExample:\r\n\r\n**Wo wohnst du?**\r\nWhere do you live?\r\n\r\n**Wer bist du?**\r\nWho are you?\r\n\r\nNow the station text continues:\r\n\r\n**Sie ist jung. Er ist jung.**\r\nShe is young. He is young.\r\n\r\n**Sie sind verliebt.**\r\nThey are in love.\r\n\r\n**Der Mann winkt. Die Frau geht.**\r\nThe man waves. The woman goes.\r\n\r\nAgain:\r\n\r\n**Menschen kommen und gehen, lachen und weinen. Ein Bahnhof.**\r\n\r\nThis text connects grammar with real life. We learn verbs, pronouns, emotions, and questions all in one small reading.\r\n\r\nNow let’s talk about **sein**, the verb “to be”.\r\n\r\nGerman:\r\n\r\n**ich bin** = I am\r\n**du bist** = you are\r\n**er ist** = he is\r\n**sie ist** = she is\r\n**es ist** = it is\r\n**sie sind** = they are\r\n\r\nExamples:\r\n\r\n**Ich bin glücklich.**\r\nI am happy.\r\n\r\n**Du bist glücklich.**\r\nYou are happy.\r\n\r\n**Er ist glücklich.**\r\nHe is happy.\r\n\r\n**Sie ist glücklich.**\r\nShe is happy.\r\n\r\n**Es ist glücklich.**\r\nIt is happy.\r\n\r\n**Sie sind glücklich.**\r\nThey are happy.\r\n\r\nCommon mistake:\r\n\r\nUsing **ist** for everyone.\r\n\r\nWrong: **Ich ist glücklich.**\r\nCorrect: **Ich bin glücklich.**\r\n\r\nWrong: **Du ist glücklich.**\r\nCorrect: **Du bist glücklich.**\r\n\r\nWrong: **Sie ist Touristen.**\r\nIf “sie” means they, correct: **Sie sind Touristen.**\r\n\r\nNow next section is **Ich**.\r\n\r\nThat means “I”.\r\n\r\nHere two people introduce themselves.\r\n\r\nFirst person:\r\n\r\n**Ich heiße Jan Schöne.**\r\nMy name is Jan Schöne.\r\n\r\n**Ich bin Sänger.**\r\nI am a singer.\r\n\r\n**Ich wohne in Berlin.**\r\nI live in Berlin.\r\n\r\n**Ich arbeite in Potsdam.**\r\nI work in Potsdam.\r\n\r\n**Ich spiele gern Klavier.**\r\nI like playing piano.\r\n\r\nVery useful sentences.\r\n\r\nLet’s repeat:\r\n\r\n**Ich heiße...**\r\nMy name is...\r\n\r\n**Ich bin...**\r\nI am...\r\n\r\n**Ich wohne in...**\r\nI live in...\r\n\r\n**Ich arbeite in...**\r\nI work in...\r\n\r\n**Ich spiele gern...**\r\nI like playing...\r\n\r\nNow second person:\r\n\r\n**Ich heiße Sara Anmut.**\r\nMy name is Sara Anmut.\r\n\r\n**Ich bin Verkäuferin.**\r\nI am a saleswoman.\r\n\r\n**Ich wohne in Hamburg.**\r\nI live in Hamburg.\r\n\r\n**Ich arbeite in Bremen.**\r\nI work in Bremen.\r\n\r\n**Ich höre gern Musik.**\r\nI like listening to music.\r\n\r\nఇక్కడ **gern** చాలా useful word.\r\n\r\n**gern** means “gladly” or “like to”.\r\n\r\nExamples:\r\n\r\n**Ich höre gern Musik.**\r\nI like listening to music.\r\n\r\n**Ich spiele gern Klavier.**\r\nI like playing piano.\r\n\r\n**Ich trinke gern Kaffee.**\r\nI like drinking coffee.\r\n\r\n**Ich lerne gern Deutsch.**\r\nI like learning German.\r\n\r\nCommon mistake:\r\n\r\nEnglish structure directly translate చేయడం.\r\n\r\nEnglish: I like music.\r\nGerman beginner sentence: **Ich höre gern Musik.**\r\nLiterally: I listen gladly to music.\r\n\r\nNow **wohnen** and **leben**.\r\n\r\nBoth can mean live, but small difference:\r\n\r\n**wohnen** means to live or reside in a place, like address/city.\r\n**leben** means to live in broader life sense.\r\n\r\nBeginner level లో:\r\n\r\n**Ich wohne in Berlin.**\r\nI live in Berlin.\r\n\r\n**Ich lebe in Berlin.**\r\nI live in Berlin.\r\n\r\nBoth okay in many contexts, but **wohnen** is more common for asking where someone lives.\r\n\r\nQuestion:\r\n\r\n**Wo wohnst du?**\r\nWhere do you live?\r\n\r\nAnswer:\r\n\r\n**Ich wohne in Berlin.**\r\n\r\nNow we come to **Du**.\r\n\r\n**Du** means informal you. Friends, classmates, children, close people.\r\n\r\nLesson 1 లో మనం **Sie** and **du** చూశాం. Lesson 2 లో **du** questions practice చేస్తున్నాం.\r\n\r\nImportant questions:\r\n\r\n**Wie heißt du?**\r\nWhat is your name?\r\n\r\n**Wo wohnst du?**\r\nWhere do you live?\r\n\r\n**Was machst du?**\r\nWhat are you doing?\r\n\r\n**Wann kommst du?**\r\nWhen are you coming?\r\n\r\n**Kommst du bald?**\r\nAre you coming soon?\r\n\r\n**Arbeitest du?**\r\nDo you work? Or are you working?\r\n\r\n**Bist du glücklich?**\r\nAre you happy?\r\n\r\nLet’s break each one.\r\n\r\n**Wie heißt du?**\r\nమీ పేరు ఏమిటి? Informal.\r\n\r\nAnswer:\r\n\r\n**Ich heiße Sara.**\r\n\r\n**Wo wohnst du?**\r\nనువ్వు ఎక్కడ ఉంటావు?\r\n\r\nAnswer:\r\n\r\n**Ich wohne in Hamburg.**\r\n\r\n**Wann kommst du?**\r\nనువ్వు ఎప్పుడు వస్తావు?\r\n\r\nAnswer:\r\n\r\n**Ich komme bald.**\r\nI am coming soon.\r\n\r\n**Arbeitest du?**\r\nనువ్వు పని చేస్తున్నావా?\r\n\r\nAnswer:\r\n\r\n**Nein, ich arbeite nicht.**\r\nNo, I am not working.\r\n\r\n**Was machst du?**\r\nనువ్వు ఏమి చేస్తున్నావు?\r\n\r\nAnswer:\r\n\r\n**Ich höre Musik.**\r\nI am listening to music.\r\n\r\n**Bist du glücklich?**\r\nనువ్వు happy గా ఉన్నావా?\r\n\r\nAnswer:\r\n\r\n**Ja, ich bin glücklich.**\r\n\r\nఇక్కడ **Ja** means yes.\r\n**Nein** means no.\r\n**nicht** means not.\r\n\r\nExample:\r\n\r\n**Ich arbeite.**\r\nI work.\r\n\r\n**Ich arbeite nicht.**\r\nI do not work.\r\n\r\n**Ich bin glücklich.**\r\nI am happy.\r\n\r\n**Ich bin nicht glücklich.**\r\nI am not happy.\r\n\r\nCommon mistake:\r\n\r\n**nicht** placement. Beginner stage లో simple pattern గుర్తుపెట్టుకోండి:\r\n\r\nVerb sentence:\r\n\r\n**Ich arbeite nicht.**\r\n\r\nAdjective sentence:\r\n\r\n**Ich bin nicht glücklich.**\r\n\r\nNow verb changes with **ich** and **du**.\r\n\r\nLet’s learn four verbs from the lesson.\r\n\r\n**kommen** = to come\r\n**ich komme** = I come\r\n**du kommst** = you come\r\n**Kommst du?** = Are you coming?\r\n\r\n**heißen** = to be called\r\n**ich heiße** = my name is\r\n**du heißt** = your name is\r\n**Heißt du Sara?** = Is your name Sara?\r\n\r\n**arbeiten** = to work\r\n**ich arbeite** = I work\r\n**du arbeitest** = you work\r\n**Arbeitest du?** = Do you work?\r\n\r\n**sein** = to be\r\n**ich bin** = I am\r\n**du bist** = you are\r\n**Bist du glücklich?** = Are you happy?\r\n\r\nSimple pattern:\r\n\r\nWith **ich**, many verbs end in **-e**.\r\n\r\n**ich komme**\r\n**ich heiße**\r\n**ich arbeite**\r\n**ich wohne**\r\n**ich höre**\r\n**ich spiele**\r\n\r\nWith **du**, many verbs end in **-st**.\r\n\r\n**du kommst**\r\n**du heißt**\r\n**du arbeitest**\r\n**du wohnst**\r\n**du hörst**\r\n**du spielst**\r\n\r\nQuestion pattern:\r\n\r\nIn German yes/no questions, verb comes first.\r\n\r\nStatement:\r\n\r\n**Du kommst bald.**\r\nYou are coming soon.\r\n\r\nQuestion:\r\n\r\n**Kommst du bald?**\r\nAre you coming soon?\r\n\r\nStatement:\r\n\r\n**Du arbeitest.**\r\nYou work.\r\n\r\nQuestion:\r\n\r\n**Arbeitest du?**\r\nDo you work?\r\n\r\nStatement:\r\n\r\n**Du bist glücklich.**\r\nYou are happy.\r\n\r\nQuestion:\r\n\r\n**Bist du glücklich?**\r\nAre you happy?\r\n\r\nThis is very important.\r\n\r\nEnglish లో do/does use చేస్తాం. German లో often verb first చేస్తే question అవుతుంది.\r\n\r\nNow let’s practice small dialogue.\r\n\r\nA: **Hallo. Wie heißt du?**\r\nB: **Ich heiße Sara. Und du?**\r\nA: **Ich heiße Jan. Wo wohnst du?**\r\nB: **Ich wohne in Hamburg.**\r\nA: **Was machst du?**\r\nB: **Ich höre Musik.**\r\nA: **Bist du glücklich?**\r\nB: **Ja, ich bin glücklich.**\r\n\r\nMeaning in Telugu:\r\n\r\nHi. నీ పేరు ఏమిటి?\r\nనా పేరు Sara. మరి నీవు?\r\nనా పేరు Jan. నువ్వు ఎక్కడ ఉంటావు?\r\nనేను Hamburg లో ఉంటాను.\r\nనువ్వు ఏమి చేస్తున్నావు?\r\nనేను music వింటున్నాను.\r\nనువ్వు happy గా ఉన్నావా?\r\nఅవును, నేను happy గా ఉన్నాను.\r\n\r\nNow final reading section: **Ein Brief**.\r\n\r\nఅంటే: A letter.\r\n\r\nJan writes a letter to Sara.\r\n\r\nThe letter starts:\r\n\r\n**Liebe Sara,**\r\nDear Sara.\r\n\r\n**Du bist nicht da.**\r\nYou are not here.\r\n\r\n**Ich bin traurig.**\r\nI am sad.\r\n\r\n**Ich spiele Klavier.**\r\nI play piano.\r\n\r\n**Ich arbeite.**\r\nI work.\r\n\r\n**Ich schreibe.**\r\nI write.\r\n\r\n**Ich warte.**\r\nI wait.\r\n\r\nThis is very emotional but simple German.\r\n\r\nLet’s learn emotion words:\r\n\r\n**glücklich** = happy\r\n**traurig** = sad\r\n**allein** = alone\r\n**verliebt** = in love\r\n\r\nExamples:\r\n\r\n**Ich bin glücklich.**\r\nI am happy.\r\n\r\n**Ich bin traurig.**\r\nI am sad.\r\n\r\n**Ich bin allein.**\r\nI am alone.\r\n\r\n**Sie sind verliebt.**\r\nThey are in love.\r\n\r\nNow questions in the letter:\r\n\r\n**Wann kommst du?**\r\nWhen are you coming?\r\n\r\n**Bist du traurig?**\r\nAre you sad?\r\n\r\n**Bist du glücklich?**\r\nAre you happy?\r\n\r\n**Was machst du?**\r\nWhat are you doing?\r\n\r\n**Weinst du?**\r\nAre you crying?\r\n\r\n**Lachst du?**\r\nAre you laughing?\r\n\r\n**Arbeitest du?**\r\nAre you working?\r\n\r\n**Hörst du Musik?**\r\nAre you listening to music?\r\n\r\n**Wartest du?**\r\nAre you waiting?\r\n\r\nNotice the pattern again:\r\n\r\nVerb first question:\r\n\r\n**Weinst du?**\r\nAre you crying?\r\n\r\n**Lachst du?**\r\nAre you laughing?\r\n\r\n**Arbeitest du?**\r\nAre you working?\r\n\r\n**Wartest du?**\r\nAre you waiting?\r\n\r\nQuestion word question:\r\n\r\n**Wann kommst du?**\r\nWhen are you coming?\r\n\r\n**Was machst du?**\r\nWhat are you doing?\r\n\r\nSo German questions have two common types.\r\n\r\nType 1, question word first:\r\n\r\n**Was machst du?**\r\n**Wo wohnst du?**\r\n**Wann kommst du?**\r\n**Wie heißt du?**\r\n\r\nType 2, yes/no question, verb first:\r\n\r\n**Kommst du bald?**\r\n**Bist du glücklich?**\r\n**Arbeitest du?**\r\n**Hörst du Musik?**\r\n\r\nThis is one of the biggest grammar points in lesson 2.\r\n\r\nNow letter continues:\r\n\r\n**Du wohnst in Hamburg. Ich lebe in Berlin.**\r\nYou live in Hamburg. I live in Berlin.\r\n\r\n**Ich bin allein. Du bist allein.**\r\nI am alone. You are alone.\r\n\r\n**Aber das ist bald Vergangenheit.**\r\nBut that will soon be past.\r\n\r\n**Ich träume.**\r\nI dream.\r\n\r\n**Die Zukunft:**\r\nThe future.\r\n\r\n**Du lebst in Hamburg. Ich lebe in Hamburg.**\r\nYou live in Hamburg. I live in Hamburg.\r\n\r\n**Oder:**\r\nOr.\r\n\r\n**Ich wohne in Berlin und du wohnst auch in Berlin.**\r\nI live in Berlin and you also live in Berlin.\r\n\r\n**Du und ich. Ich und du.**\r\nYou and I. I and you.\r\n\r\n**Ich bin glücklich. Du bist glücklich.**\r\nI am happy. You are happy.\r\n\r\n**Ich schicke Blumen.**\r\nI send flowers.\r\n\r\n**Kommst du bald?**\r\nAre you coming soon?\r\n\r\n**Ich liebe dich!**\r\nI love you.\r\n\r\n**Jan**\r\n\r\nThis letter is very useful because it uses many beginner sentences in emotional context.\r\n\r\nImportant words:\r\n\r\n**Liebe Sara** = Dear Sara.\r\n**nicht da** = not here.\r\n**traurig** = sad.\r\n**warten** = to wait.\r\n**Vergangenheit** = past.\r\n**Zukunft** = future.\r\n**auch** = also.\r\n**Blumen** = flowers.\r\n**Ich liebe dich** = I love you.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, **du bist** and **ich bin** confuse చేయడం.\r\n\r\nCorrect:\r\n\r\n**Ich bin traurig.**\r\nI am sad.\r\n\r\n**Du bist traurig.**\r\nYou are sad.\r\n\r\nWrong:\r\n\r\n**Ich bist traurig.**\r\n**Du bin traurig.**\r\n\r\nSecond mistake, question order.\r\n\r\nWrong:\r\n\r\n**Du kommst bald?**\r\n\r\nIn casual speech, tone can make it question. But standard beginner German:\r\n\r\n**Kommst du bald?**\r\n\r\nThird mistake, **nicht** forget చేయడం.\r\n\r\n**Du bist da** = you are here.\r\n**Du bist nicht da** = you are not here.\r\n\r\n**Ich arbeite** = I work.\r\n**Ich arbeite nicht** = I do not work.\r\n\r\nNow let’s connect lesson 2 to lesson 1.\r\n\r\nLesson 1 gave us foundation:\r\n\r\nGreetings:\r\n**Guten Tag, Hallo, Auf Wiedersehen**\r\n\r\nName:\r\n**Mein Name ist... Ich heiße...**\r\n\r\nArticles:\r\n**der, die, das**\r\n\r\nTravel words:\r\n**Zug, Taxi, Hotel, Bahnhof**\r\n\r\nLesson 2 builds on that:\r\n\r\nNow we read small sentences:\r\n\r\n**Ein Zug kommt.**\r\nA train comes.\r\n\r\n**Ein Mann kommt.**\r\nA man comes.\r\n\r\n**Eine Frau geht.**\r\nA woman goes.\r\n\r\n**Ein Mädchen lacht.**\r\nA girl laughs.\r\n\r\nNow we use pronouns:\r\n\r\n**er, sie, es, sie**\r\n\r\nNow we use verbs:\r\n\r\n**kommt, geht, lacht, weint, winkt**\r\n\r\nNow we ask questions:\r\n\r\n**Wie heißt du?**\r\n**Wo wohnst du?**\r\n**Was machst du?**\r\n**Wann kommst du?**\r\n\r\nSo lesson 1 was like learning words. Lesson 2 is using those words in sentences.\r\n\r\nNow chapter summary.\r\n\r\nIn this lesson, we learned:\r\n\r\n**ein** and **eine**\r\n\r\n**ein Mann**\r\n**eine Frau**\r\n**ein Mädchen**\r\n\r\nPronouns:\r\n\r\n**er** = he\r\n**sie** = she\r\n**es** = it\r\n**sie** = they\r\n\r\nVerbs:\r\n\r\n**kommen** = come\r\n**gehen** = go\r\n**lachen** = laugh\r\n**weinen** = cry\r\n**winken** = wave\r\n**singen** = sing\r\n**wohnen** = live\r\n**arbeiten** = work\r\n**hören** = listen\r\n**spielen** = play\r\n**warten** = wait\r\n**lieben** = love\r\n\r\nIch sentences:\r\n\r\n**Ich heiße Jan.**\r\n**Ich bin Sänger.**\r\n**Ich wohne in Berlin.**\r\n**Ich arbeite in Potsdam.**\r\n**Ich spiele gern Klavier.**\r\n\r\nDu questions:\r\n\r\n**Wie heißt du?**\r\n**Wo wohnst du?**\r\n**Was machst du?**\r\n**Wann kommst du?**\r\n**Kommst du bald?**\r\n**Arbeitest du?**\r\n**Bist du glücklich?**\r\n\r\nEmotion words:\r\n\r\n**glücklich** = happy\r\n**traurig** = sad\r\n**allein** = alone\r\n**verliebt** = in love\r\n\r\nLetter phrases:\r\n\r\n**Liebe Sara** = Dear Sara\r\n**Ich bin traurig** = I am sad\r\n**Ich warte** = I wait\r\n**Ich liebe dich** = I love you\r\n\r\nNow practical analogy.\r\n\r\nGerman learning is like watching a movie with subtitles.\r\n\r\nLesson 1 gave you the characters and places.\r\nTrain, taxi, hotel, people, names.\r\n\r\nLesson 2 starts the movie.\r\nPeople come and go.\r\nA girl laughs.\r\nA woman cries.\r\nA man says goodbye.\r\nSomeone writes a letter.\r\nSomeone waits.\r\nSomeone asks, “Wann kommst du?”\r\n\r\nSo now German is not only words. German is becoming a story.\r\n\r\nAnd that’s how language becomes alive.\r\n\r\nNow quiz time.\r\n\r\nQuestion 1: **ein Mann** అంటే ఏమిటి?\r\n\r\nQuestion 2: **eine Frau** అంటే ఏమిటి?\r\n\r\nQuestion 3: **das Mädchen** కి pronoun ఏమిటి? er, sie, లేదా es?\r\n\r\nQuestion 4: **Er wohnt in Berlin** meaning ఏమిటి?\r\n\r\nQuestion 5: **Sie macht ein Interview** లో **sie** meaning ఏమిటి?\r\n\r\nQuestion 6: **Menschen kommen und gehen** meaning ఏమిటి?\r\n\r\nQuestion 7: German లో “Where do you live?” informal గా ఎలా అడుగుతారు?\r\n\r\nQuestion 8: **Ich bin traurig** meaning ఏమిటి?\r\n\r\nQuestion 9: German yes/no question లో verb ఎక్కడ వస్తుంది?\r\n\r\nQuestion 10: **Ich liebe dich** meaning ఏమిటి?\r\n\r\nAnswers:\r\n\r\n1. A man.\r\n2. A woman.\r\n3. es.\r\n4. He lives in Berlin.\r\n5. she.\r\n6. People come and go.\r\n7. Wo wohnst du?\r\n8. I am sad.\r\n9. Verb comes first. Example: Kommst du? Bist du? Arbeitest du?\r\n10. I love you.\r\n\r\nOutro:\r\n\r\nFriends, lesson 2 లో మనం German చదవడం start చేశాం. Don’t try to memorize everything in one day. First sentences repeat చేయండి.\r\n\r\n**Ein Mann kommt.**\r\n**Eine Frau geht.**\r\n**Ein Mädchen lacht.**\r\n**Ich heiße...**\r\n**Ich wohne in...**\r\n**Was machst du?**\r\n**Wann kommst du?**\r\n\r\nఈ sentences daily repeat చేస్తే German slowly natural అవుతుంది.\r\n\r\nDanke schön. Auf Wiedersehen. See you in the next lesson.', 'https://silver-llama-257051.hostingersite.com/uploads/audio/1781100573-a1-chapter2.m4a', 1, '2026-06-21 23:44:29', '2026-06-21 23:44:29');
INSERT INTO `lesson_translations` (`id`, `lesson_id`, `language_code`, `title`, `notes`, `audio_url`, `is_published`, `created_at`, `updated_at`) VALUES
(3, 3, 'te', 'స్టేషన్‌లో మెషీన్లు, లగేజ్, మరియు “నా/నీ”', 'Podcast Title: German Telugu Lesson 3, Fokus Hören\r\n\r\nIntro music, soft and calm.\r\n\r\nNamaskaram friends. Welcome back to our German learning podcast.\r\n\r\nఈ రోజు మనం German Lesson 3 నేర్చుకోబోతున్నాం. ఈ lesson పేరు **Fokus Hören**. అంటే **Listening focus**. తెలుగులో చెప్పాలంటే, వినడం మీద focus చేసే lesson.\r\n\r\nLesson 1 లో మనం greetings, names, numbers, station words, articles నేర్చుకున్నాం.\r\n\r\nLesson 2 లో మనం reading start చేశాం. People గురించి sentences చదివాం. **ein Mann, eine Frau, ein Mädchen**, అలాగే **er, sie, es**, verbs like **kommt, geht, lacht, weint** నేర్చుకున్నాం.\r\n\r\nఇప్పుడు Lesson 3 లో మనం listening practice కి వస్తున్నాం. German విన్నప్పుడు ఎలా అర్థం చేసుకోవాలి, wrong machine, phone conversation, possession words, luggage numbers ఇలా real-life situations నేర్చుకుంటాం.\r\n\r\nఈ lesson లో main concepts:\r\n\r\n**kein** and **keine**\r\nఅంటే “not a” or “no”.\r\n\r\n**Das ist kein Geldautomat.**\r\nThis is not an ATM.\r\n\r\n**Das ist ein Fahrkartenautomat.**\r\nThis is a ticket machine.\r\n\r\nతర్వాత phone conversations.\r\n\r\nతర్వాత **mein, meine, dein, deine**\r\nఅంటే my and your.\r\n\r\nతర్వాత **sein, seine, ihr, ihre**\r\nఅంటే his, her, its, their.\r\n\r\nచివరిగా polite **Ihr, Ihre**\r\nఅంటే your, formal.\r\n\r\nSo relax. Slowly వినండి. Repeat చేయండి. ఈ lesson German listening and speaking కి చాలా useful.\r\n\r\nLet’s start.\r\n\r\nFirst situation: station లో machine దగ్గర confusion.\r\n\r\nఒక person machine దగ్గర నిలబడి ఉన్నాడు. అతను money తీసుకోవాలని try చేస్తున్నాడు. కానీ money రావడం లేదు. ఎందుకంటే అది ATM కాదు. అది ticket machine.\r\n\r\nGerman sentence:\r\n\r\n**Da kommt kein Geld.**\r\n\r\nMeaning:\r\n\r\nఅక్కడ డబ్బు రావడం లేదు.\r\n\r\nBreakdown:\r\n\r\n**da** = there\r\n**kommt** = comes\r\n**kein Geld** = no money\r\n\r\nSo full meaning:\r\n\r\nThere is no money coming out.\r\n\r\nఇప్పుడు అతను అడగవచ్చు:\r\n\r\n**Ist der Geldautomat kaputt?**\r\n\r\nMeaning:\r\n\r\nATM broken అయిందా?\r\n\r\n**Ist** = is\r\n**der Geldautomat** = the ATM\r\n**kaputt** = broken\r\n\r\nBut the other person says:\r\n\r\n**Das ist kein Geldautomat.**\r\n\r\nMeaning:\r\n\r\nఇది ATM కాదు.\r\n\r\nThen:\r\n\r\n**Das ist ein Fahrkartenautomat.**\r\n\r\nMeaning:\r\n\r\nఇది ticket machine.\r\n\r\nVery useful words:\r\n\r\n**der Geldautomat** = ATM\r\n**der Fahrkartenautomat** = ticket machine\r\n**die Fahrkarte** = ticket\r\n**kaputt** = broken\r\n**kein Geld** = no money\r\n\r\nNow the important grammar is **kein**.\r\n\r\nIn lesson 2, we learned:\r\n\r\n**ein Mann** = a man\r\n**eine Frau** = a woman\r\n**ein Baby** = a baby\r\n\r\nNow negative form:\r\n\r\n**kein Mann** = not a man\r\n**keine Frau** = not a woman\r\n**kein Baby** = not a baby\r\n\r\nSimple rule:\r\n\r\nFor **der** words, use **kein**.\r\n\r\n**der Geldautomat**\r\n**ein Geldautomat**\r\n**kein Geldautomat**\r\n\r\nFor **die** words, use **keine**.\r\n\r\n**die Sängerin**\r\n**eine Sängerin**\r\n**keine Sängerin**\r\n\r\nFor **das** words, use **kein**.\r\n\r\n**das Klavier**\r\n**ein Klavier**\r\n**kein Klavier**\r\n\r\nPlural also uses **keine**.\r\n\r\n**die Polizeiautos**\r\n**Polizeiautos**\r\n**keine Polizeiautos**\r\n\r\nLet’s repeat:\r\n\r\n**ein Geldautomat, kein Geldautomat**\r\n**eine Sängerin, keine Sängerin**\r\n**ein Klavier, kein Klavier**\r\n**Polizeiautos, keine Polizeiautos**\r\n\r\nWhy is this important?\r\n\r\nBecause in real life, you often need to say something is not something.\r\n\r\nExample:\r\n\r\nThis is not an ATM.\r\n**Das ist kein Geldautomat.**\r\n\r\nThis is not a taxi.\r\n**Das ist kein Taxi.**\r\n\r\nThis is not a ticket.\r\n**Das ist keine Fahrkarte.**\r\n\r\nThese are not police cars.\r\n**Das sind keine Polizeiautos.**\r\n\r\nCommon mistake:\r\n\r\nStudents use **nicht** instead of **kein**.\r\n\r\nFor nouns, especially with ein/eine, use **kein/keine**.\r\n\r\nWrong:\r\n\r\n**Das ist nicht ein Geldautomat.**\r\n\r\nBetter beginner German:\r\n\r\n**Das ist kein Geldautomat.**\r\n\r\nWrong:\r\n\r\n**Das ist nicht eine Sängerin.**\r\n\r\nCorrect:\r\n\r\n**Das ist keine Sängerin.**\r\n\r\nRemember:\r\n\r\n**nicht** usually negates verbs, adjectives, or full ideas.\r\n**kein/keine** negates nouns with a/an/no.\r\n\r\nExample:\r\n\r\n**Ich arbeite nicht.**\r\nI do not work.\r\n\r\n**Das ist kein Radio.**\r\nThat is not a radio.\r\n\r\nNow let’s create a small dialogue.\r\n\r\nPerson A:\r\n\r\n**Verzeihung.**\r\n\r\nMeaning:\r\n\r\nExcuse me.\r\n\r\nPerson B:\r\n\r\n**Ja, bitte?**\r\n\r\nMeaning:\r\n\r\nYes, please? Or yes, how can I help?\r\n\r\nPerson A:\r\n\r\n**Da kommt kein Geld. Ist der Geldautomat kaputt?**\r\n\r\nMeaning:\r\n\r\nNo money is coming. Is the ATM broken?\r\n\r\nPerson B:\r\n\r\n**Das ist kein Geldautomat. Das ist ein Fahrkartenautomat.**\r\n\r\nMeaning:\r\n\r\nThis is not an ATM. This is a ticket machine.\r\n\r\nPerson A:\r\n\r\n**Das ist kein Geldautomat?**\r\n\r\nMeaning:\r\n\r\nThis is not an ATM?\r\n\r\nPerson B:\r\n\r\n**Nein, der Geldautomat ist dort.**\r\n\r\nMeaning:\r\n\r\nNo, the ATM is there.\r\n\r\nPerson A:\r\n\r\n**Oh, danke!**\r\n\r\nMeaning:\r\n\r\nOh, thank you.\r\n\r\nThis is a very natural German conversation. You can use this structure in many places.\r\n\r\nNow let’s vary it with other machines.\r\n\r\n**der Saftautomat** = juice machine\r\n**der Bierautomat** = beer machine\r\n**der Kaugummiautomat** = chewing gum machine\r\n**der Teeautomat** = tea machine\r\n**der Kaffeeautomat** = coffee machine\r\n**der Würstchenautomat** = sausage machine\r\n**der Bonbonautomat** = candy machine\r\n\r\nExample 1:\r\n\r\n**Da kommt kein Saft. Ist der Saftautomat kaputt?**\r\n\r\nNo juice is coming. Is the juice machine broken?\r\n\r\nAnswer:\r\n\r\n**Das ist kein Saftautomat. Das ist ein Bierautomat.**\r\n\r\nThis is not a juice machine. This is a beer machine.\r\n\r\nExample 2:\r\n\r\n**Da kommt kein Kaugummi. Ist der Kaugummiautomat kaputt?**\r\n\r\nNo chewing gum is coming. Is the chewing gum machine broken?\r\n\r\nAnswer:\r\n\r\n**Das ist kein Kaugummiautomat. Das ist ein Geldautomat.**\r\n\r\nThis is not a chewing gum machine. This is an ATM.\r\n\r\nExample 3:\r\n\r\n**Da kommt kein Tee. Ist der Teeautomat kaputt?**\r\n\r\nNo tea is coming. Is the tea machine broken?\r\n\r\nAnswer:\r\n\r\n**Das ist kein Teeautomat. Das ist ein Kaffeeautomat.**\r\n\r\nThis is not a tea machine. This is a coffee machine.\r\n\r\nSee the pattern. Once you know the pattern, you can create many sentences.\r\n\r\nNow let’s move to phone conversations.\r\n\r\nThe chapter has **Drei Telefongespräche**. That means three phone conversations.\r\n\r\nImportant phone phrases:\r\n\r\n**Hallo.**\r\nHello.\r\n\r\n**Guten Tag.**\r\nGood day.\r\n\r\n**Wo bist du?**\r\nWhere are you?\r\n\r\n**Wo sind Sie?**\r\nWhere are you? Formal.\r\n\r\n**Ich bin in Hamburg.**\r\nI am in Hamburg.\r\n\r\n**Bist du am Bahnhof?**\r\nAre you at the station?\r\n\r\n**Sind Sie in Hamburg?**\r\nAre you in Hamburg? Formal.\r\n\r\nNow we see again **du** and **Sie**.\r\n\r\nLesson 1 లో నేర్చుకున్నాం:\r\n\r\n**du** informal.\r\n**Sie** formal.\r\n\r\nPhone with friend:\r\n\r\n**Wo bist du?**\r\n\r\nPhone with official or formal person:\r\n\r\n**Wo sind Sie?**\r\n\r\nExample:\r\n\r\nFriend:\r\n\r\nA: **Hallo, Anna. Wo bist du?**\r\nB: **Ich bin am Bahnhof.**\r\n\r\nFormal:\r\n\r\nA: **Guten Tag, Herr Mahler. Wo sind Sie?**\r\nB: **Ich bin in Hamburg.**\r\n\r\nImportant word:\r\n\r\n**am Bahnhof** = at the station\r\n\r\n**am** means **an dem**, at the.\r\n\r\nSo:\r\n\r\n**Ich bin am Bahnhof.**\r\nI am at the station.\r\n\r\n**Ich bin in Berlin.**\r\nI am in Berlin.\r\n\r\n**Ich bin in Hamburg.**\r\nI am in Hamburg.\r\n\r\nNow phone conversations also use object identification:\r\n\r\n**Ist das ein Radio?**\r\n\r\nMeaning:\r\n\r\nIs that a radio?\r\n\r\nAnswer:\r\n\r\n**Nein, das ist kein Radio.**\r\n\r\nNo, that is not a radio.\r\n\r\n**Das ist kein Klavier.**\r\n\r\nThat is not a piano.\r\n\r\n**Meine Frau spielt Klavier.**\r\n\r\nMy wife plays piano.\r\n\r\nHere we hear **mein/meine** for the first time.\r\n\r\nBut before possessives, let’s finish **ist** and **sind**.\r\n\r\n**ist** = is\r\n**sind** = are\r\n\r\nSingular:\r\n\r\n**Das ist ein Radio.**\r\nThat is a radio.\r\n\r\n**Das ist keine Sängerin.**\r\nThat is not a singer.\r\n\r\nPlural:\r\n\r\n**Das sind Polizeiautos.**\r\nThose are police cars.\r\n\r\n**Das sind keine Krankenwagen.**\r\nThose are not ambulances.\r\n\r\nWords:\r\n\r\n**das Radio** = radio\r\n**das Klavier** = piano\r\n**die Sängerin** = female singer\r\n**der Krankenwagen** = ambulance\r\n**das Polizeiauto** = police car\r\n**der Unfall** = accident\r\n\r\nExample from lesson:\r\n\r\n**Hier ist ein Unfall.**\r\n\r\nMeaning:\r\n\r\nThere is an accident here.\r\n\r\n**Das sind Polizeiautos.**\r\n\r\nMeaning:\r\n\r\nThose are police cars.\r\n\r\n**Das sind keine Krankenwagen.**\r\n\r\nMeaning:\r\n\r\nThose are not ambulances.\r\n\r\nCommon mistake:\r\n\r\nUsing **ist** for plural.\r\n\r\nWrong:\r\n\r\n**Das ist Polizeiautos.**\r\n\r\nCorrect:\r\n\r\n**Das sind Polizeiautos.**\r\n\r\nWrong:\r\n\r\n**Das ist keine Krankenwagen.**\r\n\r\nCorrect:\r\n\r\n**Das sind keine Krankenwagen.**\r\n\r\nUse **ist** for one thing.\r\nUse **sind** for many things.\r\n\r\nNow let’s move to the station conversation: **Am Bahnhof**.\r\n\r\nIn this part, people are at the station near a train. The dialogue includes family words and possession.\r\n\r\nImportant sentences:\r\n\r\n**Wie geht’s?**\r\n\r\nMeaning:\r\n\r\nHow are you?\r\n\r\nFull form is **Wie geht es?** But common spoken German is:\r\n\r\n**Wie geht’s?**\r\n\r\nAnswer can be:\r\n\r\n**Gut.**\r\nGood.\r\n\r\n**Sehr gut.**\r\nVery good.\r\n\r\n**Nicht so gut.**\r\nNot so good.\r\n\r\nNext sentence:\r\n\r\n**Wo sind deine Kinder?**\r\n\r\nMeaning:\r\n\r\nWhere are your children?\r\n\r\n**deine Kinder** = your children\r\n\r\nAnswer:\r\n\r\n**Meine Kinder sind dort.**\r\n\r\nMeaning:\r\n\r\nMy children are there.\r\n\r\n**meine Kinder** = my children\r\n**dort** = there\r\n\r\nNext:\r\n\r\n**Mein Sohn Ralf ist zehn.**\r\n\r\nMeaning:\r\n\r\nMy son Ralf is ten.\r\n\r\n**mein Sohn** = my son\r\n**ist zehn** = is ten years old\r\n\r\nIn German, to say age:\r\n\r\n**Ich bin zehn.**\r\n\r\nLiterally: I am ten.\r\n\r\n**Mein Sohn ist zehn.**\r\n\r\nMy son is ten.\r\n\r\nQuestion:\r\n\r\n**Wie alt ist deine Tochter?**\r\n\r\nMeaning:\r\n\r\nHow old is your daughter?\r\n\r\n**Wie alt** = how old\r\n**deine Tochter** = your daughter\r\n\r\nAnswer example:\r\n\r\n**Meine Tochter ist acht.**\r\n\r\nMy daughter is eight.\r\n\r\nNow another sentence:\r\n\r\n**Sag mal, was ist das denn?**\r\n\r\nMeaning:\r\n\r\nTell me, what is that actually?\r\n\r\nThis is spoken German. **Sag mal** is like “tell me” or “hey, tell me.”\r\n**was ist das denn?** means “what is that then?”\r\n\r\nNext:\r\n\r\n**Aha, das ist dein Kamel.**\r\n\r\nMeaning:\r\n\r\nAh, that is your camel.\r\n\r\nFunny sentence. Maybe a toy camel or something surprising.\r\n\r\nNext:\r\n\r\n**Los, das Taxi wartet.**\r\n\r\nMeaning:\r\n\r\nCome on, the taxi is waiting.\r\n\r\n**Los** = come on\r\n**wartet** = waits/is waiting\r\n\r\nNow main grammar: **mein/meine** and **dein/deine**.\r\n\r\n**mein** = my\r\n**dein** = your informal\r\n\r\nBut German changes based on the noun.\r\n\r\nFor masculine and neuter singular, use:\r\n\r\n**mein** and **dein**\r\n\r\nExamples:\r\n\r\n**mein Saft**\r\nmy juice\r\n\r\n**mein Sohn**\r\nmy son\r\n\r\n**mein Kind**\r\nmy child\r\n\r\n**mein Telefon**\r\nmy telephone\r\n\r\n**dein Saft**\r\nyour juice\r\n\r\n**dein Sohn**\r\nyour son\r\n\r\n**dein Kind**\r\nyour child\r\n\r\n**dein Telefon**\r\nyour telephone\r\n\r\nFor feminine singular and plural, use:\r\n\r\n**meine** and **deine**\r\n\r\nExamples:\r\n\r\n**meine Zeitung**\r\nmy newspaper\r\n\r\n**meine Tochter**\r\nmy daughter\r\n\r\n**meine Kinder**\r\nmy children\r\n\r\n**meine Blumen**\r\nmy flowers\r\n\r\n**deine Zeitung**\r\nyour newspaper\r\n\r\n**deine Tochter**\r\nyour daughter\r\n\r\n**deine Kinder**\r\nyour children\r\n\r\n**deine Blumen**\r\nyour flowers\r\n\r\nSimple rule:\r\n\r\n**der** and **das** words use **mein/dein**.\r\n**die** words and plural use **meine/deine**.\r\n\r\nExamples:\r\n\r\n**der Saft**\r\n**mein Saft**\r\n**dein Saft**\r\n\r\n**das Telefon**\r\n**mein Telefon**\r\n**dein Telefon**\r\n\r\n**die Zeitung**\r\n**meine Zeitung**\r\n**deine Zeitung**\r\n\r\n**die Blumen** plural\r\n**meine Blumen**\r\n**deine Blumen**\r\n\r\nCommon mistake:\r\n\r\nUsing **mein** for everything.\r\n\r\nWrong:\r\n\r\n**mein Zeitung**\r\n\r\nCorrect:\r\n\r\n**meine Zeitung**\r\n\r\nWrong:\r\n\r\n**dein Kinder**\r\n\r\nCorrect:\r\n\r\n**deine Kinder**\r\n\r\nWrong:\r\n\r\n**meine Sohn**\r\n\r\nCorrect:\r\n\r\n**mein Sohn**\r\n\r\nSo always connect possessive word with article/gender.\r\n\r\nNow let’s practice.\r\n\r\n**Das ist mein Saft.**\r\nThis is my juice.\r\n\r\n**Das ist meine Zeitung.**\r\nThis is my newspaper.\r\n\r\n**Das ist mein Telefon.**\r\nThis is my telephone.\r\n\r\n**Das sind meine Blumen.**\r\nThese are my flowers.\r\n\r\nNow your:\r\n\r\n**Das ist dein Saft.**\r\nThis is your juice.\r\n\r\n**Das ist deine Zeitung.**\r\nThis is your newspaper.\r\n\r\n**Das ist dein Telefon.**\r\nThis is your telephone.\r\n\r\n**Das sind deine Blumen.**\r\nThese are your flowers.\r\n\r\nNow let’s move to **sein** and **ihr**.\r\n\r\nIn the chapter, there is a conversation:\r\n\r\n**Mama, wo ist mein Ball?**\r\n\r\nMeaning:\r\n\r\nMom, where is my ball?\r\n\r\nHere **mein Ball** = my ball.\r\n\r\nThen the lesson brings examples:\r\n\r\n**Vanessa ist traurig. Ihr Auto ist kaputt.**\r\n\r\nMeaning:\r\n\r\nVanessa is sad. Her car is broken.\r\n\r\nWhy **ihr Auto**?\r\n\r\nBecause Vanessa is female, so **her** = **ihr**.\r\n\r\nAnother example:\r\n\r\n**Uwe ist glücklich. Sein Ball ist da.**\r\n\r\nMeaning:\r\n\r\nUwe is happy. His ball is there.\r\n\r\nWhy **sein Ball**?\r\n\r\nBecause Uwe is male, so **his** = **sein**.\r\n\r\nNow grammar:\r\n\r\nFor male owner:\r\n\r\n**sein** = his\r\n\r\nFor female owner:\r\n\r\n**ihr** = her\r\n\r\nFor neuter owner:\r\n\r\n**sein** = its\r\n\r\nFor plural owner:\r\n\r\n**ihr** = their\r\n\r\nExamples:\r\n\r\nMale owner:\r\n\r\n**Uwe hat einen Ball. Sein Ball ist da.**\r\nUwe has a ball. His ball is there.\r\n\r\nFemale owner:\r\n\r\n**Vanessa hat ein Auto. Ihr Auto ist kaputt.**\r\nVanessa has a car. Her car is broken.\r\n\r\nNeuter owner:\r\n\r\n**Das Baby weint. Seine Mutter ist nicht da.**\r\nThe baby cries. Its mother is not there.\r\n\r\nPlural owner:\r\n\r\n**Die Kinder sind glücklich. Ihre Mutter ist da.**\r\nThe children are happy. Their mother is there.\r\n\r\nNow, just like **mein/meine**, **sein/ihr** also changes based on the noun.\r\n\r\nFor masculine and neuter nouns:\r\n\r\n**sein Ball** = his ball\r\n**ihr Ball** = her ball\r\n**sein Auto** = his car\r\n**ihr Auto** = her car\r\n\r\nFor feminine nouns and plural:\r\n\r\n**seine Flasche** = his bottle\r\n**ihre Flasche** = her bottle\r\n**seine Fahrkarten** = his tickets\r\n**ihre Fahrkarten** = her tickets\r\n\r\nWords:\r\n\r\n**der Ball** = ball\r\n**die Flasche** = bottle\r\n**das Auto** = car\r\n**die Fahrkarten** = tickets\r\n**die Mutter** = mother\r\n**der Sohn** = son\r\n\r\nCommon mistake:\r\n\r\nStudents confuse owner gender and object gender.\r\n\r\nVery important:\r\n\r\nThe first part, **sein** or **ihr**, depends on the owner.\r\n\r\nBut the ending, like **sein/seine** or **ihr/ihre**, depends on the object.\r\n\r\nExample:\r\n\r\nVanessa is female. So her = **ihr**.\r\n\r\n**der Ball** masculine:\r\n\r\n**ihr Ball**\r\nher ball\r\n\r\n**die Flasche** feminine:\r\n\r\n**ihre Flasche**\r\nher bottle\r\n\r\n**das Auto** neuter:\r\n\r\n**ihr Auto**\r\nher car\r\n\r\n**die Fahrkarten** plural:\r\n\r\n**ihre Fahrkarten**\r\nher tickets\r\n\r\nNow Uwe is male. So his = **sein**.\r\n\r\n**der Ball**:\r\n\r\n**sein Ball**\r\n\r\n**die Flasche**:\r\n\r\n**seine Flasche**\r\n\r\n**das Auto**:\r\n\r\n**sein Auto**\r\n\r\n**die Fahrkarten**:\r\n\r\n**seine Fahrkarten**\r\n\r\nThis is a big concept, so listen again slowly.\r\n\r\nOwner male:\r\n\r\n**sein Ball, seine Flasche, sein Auto, seine Fahrkarten**\r\n\r\nOwner female:\r\n\r\n**ihr Ball, ihre Flasche, ihr Auto, ihre Fahrkarten**\r\n\r\nOwner plural:\r\n\r\n**ihr Ball, ihre Flasche, ihr Auto, ihre Fahrkarten**\r\n\r\nNow let’s create small texts like the lesson.\r\n\r\n**Der Reporter ist allein. Seine Frau wohnt in Wien.**\r\n\r\nMeaning:\r\n\r\nThe reporter is alone. His wife lives in Vienna.\r\n\r\nWhy **seine Frau**?\r\n\r\nReporter is male, owner male. But Frau is feminine, so **seine Frau**.\r\n\r\nNext:\r\n\r\n**Die Mutter wartet. Ihr Sohn kommt nicht.**\r\n\r\nMeaning:\r\n\r\nThe mother waits. Her son does not come.\r\n\r\nWhy **ihr Sohn**?\r\n\r\nMother is female, owner female. Sohn is masculine, so **ihr Sohn**.\r\n\r\nNext:\r\n\r\n**Das Mädchen weint. Seine Mutter ist nicht da.**\r\n\r\nMeaning:\r\n\r\nThe girl cries. Her mother is not there.\r\n\r\nGrammatically, because **das Mädchen** is neuter, the possessive is **seine Mutter**. In natural Telugu meaning, “ఆమె తల్లి లేదు” అని చెప్పుతాం.\r\n\r\nNext:\r\n\r\n**Die Kinder sind glücklich. Ihre Mutter ist da.**\r\n\r\nMeaning:\r\n\r\nThe children are happy. Their mother is there.\r\n\r\nWhy **ihre Mutter**?\r\n\r\nChildren are plural, so their = **ihr**. Mutter is feminine, so **ihre Mutter**.\r\n\r\nNow final topic: baggage number at station.\r\n\r\nSection title:\r\n\r\n**Ihre Nummer bitte.**\r\n\r\nMeaning:\r\n\r\nYour number, please.\r\n\r\nThis is formal **your**.\r\n\r\nIn German, **Sie** formal uses:\r\n\r\n**Ihr** and **Ihre**\r\n\r\nExamples:\r\n\r\n**Ihr Koffer** = your suitcase\r\n**Ihre Tasche** = your bag\r\n**Ihr Gepäck** = your luggage\r\n**Ihre Taschen** = your bags\r\n\r\nThis is formal. Like speaking to a customer.\r\n\r\nAt baggage counter, staff may ask:\r\n\r\n**Ihre Nummer bitte.**\r\n\r\nMeaning:\r\n\r\nYour number, please.\r\n\r\nCustomer says:\r\n\r\n**Bitte Koffer Nummer eins zwei sieben.**\r\n\r\nMeaning:\r\n\r\nSuitcase number 127, please.\r\n\r\nGerman often reads numbers digit by digit in these beginner lessons.\r\n\r\n1 = eins\r\n2 = zwei\r\n7 = sieben\r\n\r\n**Nummer eins zwei sieben** = number 127.\r\n\r\nWords:\r\n\r\n**der Koffer** = suitcase\r\n**die Tasche** = bag\r\n**das Gepäck** = luggage\r\n**die Taschen** = bags\r\n\r\nNow sentences:\r\n\r\n**Das ist Ihr Koffer.**\r\n\r\nMeaning:\r\n\r\nThis is your suitcase.\r\n\r\n**Das ist Ihre Tasche.**\r\n\r\nMeaning:\r\n\r\nThis is your bag.\r\n\r\n**Ihr Gepäck ist komplett.**\r\n\r\nMeaning:\r\n\r\nYour luggage is complete.\r\n\r\n**Ihre Taschen sind nicht da.**\r\n\r\nMeaning:\r\n\r\nYour bags are not there.\r\n\r\nNow see **Ihr/Ihre** follows the same gender rule.\r\n\r\n**der Koffer**\r\n**Ihr Koffer**\r\n\r\n**die Tasche**\r\n**Ihre Tasche**\r\n\r\n**das Gepäck**\r\n**Ihr Gepäck**\r\n\r\n**die Taschen** plural\r\n**Ihre Taschen**\r\n\r\nCommon mistake:\r\n\r\nConfusing **ihr** her/their with **Ihr** formal your.\r\n\r\nSmall letter makes a big difference in writing.\r\n\r\n**ihr Koffer** can mean her suitcase or their suitcase.\r\n**Ihr Koffer** means your suitcase, formal.\r\n\r\nIn speaking, they sound same. Context tells meaning.\r\n\r\nIf you are at a counter and staff says:\r\n\r\n**Ihr Koffer ist da.**\r\n\r\nIt means:\r\n\r\nYour suitcase is here.\r\n\r\nNow let’s connect all lesson 3 concepts in one real-life scene.\r\n\r\nYou are at Hauptbahnhof.\r\n\r\nFirst, you go to a machine.\r\n\r\nYou say:\r\n\r\n**Da kommt kein Geld. Ist der Geldautomat kaputt?**\r\n\r\nSomeone says:\r\n\r\n**Das ist kein Geldautomat. Das ist ein Fahrkartenautomat. Der Geldautomat ist dort.**\r\n\r\nThen your friend calls:\r\n\r\n**Hallo, wo bist du?**\r\n\r\nYou answer:\r\n\r\n**Ich bin am Bahnhof.**\r\n\r\nYour friend asks:\r\n\r\n**Bist du glücklich?**\r\n\r\nYou say:\r\n\r\n**Nein, ich bin nicht glücklich. Mein Koffer ist nicht da.**\r\n\r\nThen you go to baggage counter.\r\n\r\nThe man says:\r\n\r\n**Ihre Nummer bitte.**\r\n\r\nYou say:\r\n\r\n**Bitte Koffer Nummer eins zwei sieben.**\r\n\r\nHe says:\r\n\r\n**Das ist Ihr Koffer. Ihr Gepäck ist komplett.**\r\n\r\nNow you are happy.\r\n\r\n**Ich bin glücklich. Mein Koffer ist da.**\r\n\r\nSee, this lesson gives real survival German.\r\n\r\nNow let’s summarize Lesson 3.\r\n\r\nMain idea 1:\r\n\r\n**kein/keine** means not a or no.\r\n\r\n**Das ist kein Geldautomat.**\r\nThis is not an ATM.\r\n\r\n**Das ist keine Sängerin.**\r\nThis is not a singer.\r\n\r\n**Das sind keine Polizeiautos.**\r\nThese are not police cars.\r\n\r\nMain idea 2:\r\n\r\n**ist** for singular, **sind** for plural.\r\n\r\n**Das ist ein Radio.**\r\nThat is a radio.\r\n\r\n**Das sind Polizeiautos.**\r\nThose are police cars.\r\n\r\nMain idea 3:\r\n\r\nPhone questions.\r\n\r\n**Wo bist du?**\r\nWhere are you?\r\n\r\n**Wo sind Sie?**\r\nWhere are you? Formal.\r\n\r\n**Ich bin am Bahnhof.**\r\nI am at the station.\r\n\r\nMain idea 4:\r\n\r\nPossessive words.\r\n\r\n**mein** = my\r\n**dein** = your informal\r\n**sein** = his or its\r\n**ihr** = her or their\r\n**Ihr** = your formal\r\n\r\nMain idea 5:\r\n\r\nGender and plural change the ending.\r\n\r\n**mein Saft**\r\n**meine Zeitung**\r\n**mein Telefon**\r\n**meine Blumen**\r\n\r\n**dein Saft**\r\n**deine Zeitung**\r\n**dein Telefon**\r\n**deine Blumen**\r\n\r\n**sein Ball**\r\n**seine Flasche**\r\n\r\n**ihr Auto**\r\n**ihre Fahrkarten**\r\n\r\n**Ihr Koffer**\r\n**Ihre Tasche**\r\n\r\nNow practical analogy.\r\n\r\nThink of German grammar like luggage tags at a railway station.\r\n\r\nEvery noun has a tag:\r\n\r\n**der, die, das**, or plural.\r\n\r\nWhen you say my, your, his, her, the possessive word must match that tag.\r\n\r\nIf the luggage tag says **der** or **das**, you often use:\r\n\r\n**mein, dein, sein, ihr, Ihr**\r\n\r\nIf the luggage tag says **die** or plural, you often use:\r\n\r\n**meine, deine, seine, ihre, Ihre**\r\n\r\nSo don’t memorize randomly. Look at the noun’s tag first.\r\n\r\n**der Koffer**\r\nYour suitcase: **Ihr Koffer**\r\n\r\n**die Tasche**\r\nYour bag: **Ihre Tasche**\r\n\r\n**das Gepäck**\r\nYour luggage: **Ihr Gepäck**\r\n\r\n**die Taschen**\r\nYour bags: **Ihre Taschen**\r\n\r\nThat’s the trick.\r\n\r\nNow quiz time.\r\n\r\nQuestion 1: **Das ist kein Geldautomat** meaning ఏమిటి?\r\n\r\nQuestion 2: **kein** and **keine** ఎప్పుడు use చేస్తాం?\r\n\r\nQuestion 3: **Das ist ein Fahrkartenautomat** meaning ఏమిటి?\r\n\r\nQuestion 4: **Ist der Geldautomat kaputt?** meaning ఏమిటి?\r\n\r\nQuestion 5: **Wo bist du?** meaning ఏమిటి?\r\n\r\nQuestion 6: **Mein Sohn ist zehn** meaning ఏమిటి?\r\n\r\nQuestion 7: **deine Kinder** meaning ఏమిటి?\r\n\r\nQuestion 8: Vanessa is female. How do you say “her car” in German?\r\n\r\nQuestion 9: Formal German లో “your suitcase” ఎలా చెప్తారు?\r\n\r\nQuestion 10: **Ihre Nummer bitte** meaning ఏమిటి?\r\n\r\nAnswers:\r\n\r\n1. This is not an ATM.\r\n2. Noun ని negative చేయడానికి, like not a/no.\r\n3. This is a ticket machine.\r\n4. Is the ATM broken?\r\n5. Where are you? Informal.\r\n6. My son is ten.\r\n7. Your children. Informal.\r\n8. ihr Auto.\r\n9. Ihr Koffer.\r\n10. Your number, please.\r\n\r\nOutro:\r\n\r\nFriends, Lesson 3 చాలా important because ఇక్కడ German real listening situations మొదలవుతున్నాయి.\r\n\r\nMachine దగ్గర confusion:\r\n\r\n**Das ist kein Geldautomat.**\r\n\r\nPhone conversation:\r\n\r\n**Wo bist du? Ich bin am Bahnhof.**\r\n\r\nFamily and possession:\r\n\r\n**Mein Sohn, deine Tochter, meine Kinder.**\r\n\r\nBaggage counter:\r\n\r\n**Ihre Nummer bitte. Das ist Ihr Koffer.**\r\n\r\nఈ sentences ని daily repeat చేయండి. Especially **kein/keine** and **mein/meine/dein/deine**. ఇవి German speaking లో చాలా frequently వస్తాయి.\r\n\r\nDanke schön. Auf Wiedersehen. See you in the next lesson.', 'https://silver-llama-257051.hostingersite.com/uploads/audio/1781100605-a1-chapter3.m4a', 1, '2026-06-21 23:44:29', '2026-06-21 23:44:29');
INSERT INTO `lesson_translations` (`id`, `lesson_id`, `language_code`, `title`, `notes`, `audio_url`, `is_published`, `created_at`, `updated_at`) VALUES
(4, 4, 'te', 'పేర్లు, నంబర్లు, కుటుంబం', 'Podcast Title: German Telugu Lesson 4, Fokus Sprechen\r\n\r\n\r\nNamaskaram friends. Welcome back to our German learning podcast.\r\n\r\nఈ రోజు మనం German Lesson 4 నేర్చుకోబోతున్నాం. ఈ lesson పేరు **Fokus Sprechen**. అంటే **speaking focus**. తెలుగులో చెప్పాలంటే, ఈ lesson లో మనం మాట్లాడడం మీద focus చేస్తాం.\r\n\r\nLesson 1 లో మనం greetings, names, numbers 1 to 10, station words, articles నేర్చుకున్నాం.\r\n\r\nLesson 2 లో మనం small German sentences చదవడం start చేశాం. **Ein Mann kommt, Eine Frau geht, Ein Mädchen lacht** లాంటి sentences నేర్చుకున్నాం.\r\n\r\nLesson 3 లో మనం listening practice చేశాం. **kein, keine**, phone conversations, **mein, meine, dein, deine, sein, ihr, Ihr** లాంటి possessive words నేర్చుకున్నాం.\r\n\r\nఇప్పుడు Lesson 4 లో మనం German speaking కి చాలా important అయిన things నేర్చుకుంటాం.\r\n\r\nఈ lesson లో మనం నేర్చుకునేది:\r\n\r\nGerman alphabet\r\nNames spell చేయడం\r\nCar number plates చెప్పడం\r\nGerman sounds like ä, ö, ü, au, ei, ie\r\nFormal and informal “How are you?”\r\nPhone conversation లో “Where are you?”\r\nNumbers 10 to 100\r\nAge చెప్పడం\r\nFamily గురించి చెప్పడం\r\n\r\nSo relax. Slowly వినండి. Repeat చేయండి. ఈ lesson pronunciation and speaking confidence కోసం చాలా important.\r\n\r\nLet’s start.\r\n\r\nFirst concept: **Das Alphabet**\r\n\r\nఅంటే German alphabet.\r\n\r\nEnglish alphabet లాగే German alphabet లో letters ఉంటాయి. But pronunciation కొంచెం different. Germany లో phone లో name spell చేయాలి, email చెప్పాలి, documents లో name confirm చేయాలి, car number plate చెప్పాలి. కాబట్టి alphabet చాలా important.\r\n\r\nImagine చేయండి. మీరు Bürgeramt కి call చేస్తున్నారు. వాళ్లు మీ name అడుగుతున్నారు. Your name spelling చెప్పాలి. లేదా hotel booking లో name confirm చేయాలి. అప్పుడే alphabet useful అవుతుంది.\r\n\r\nGerman alphabet slowly విందాం.\r\n\r\nA, B, C, D, E, F, G\r\nA sounds like **ఆ**\r\nB sounds like **బే**\r\nC sounds like **త్సే**\r\nD sounds like **డే**\r\nE sounds like **ఏ**\r\nF sounds like **ఎఫ్**\r\nG sounds like **గే**\r\n\r\nNow next:\r\n\r\nH, I, J, K, L, M, N\r\nH sounds like **హా**\r\nI sounds like **ఈ**\r\nJ sounds like **యాట్** or **యోట్**\r\nK sounds like **కా**\r\nL sounds like **ఎల్**\r\nM sounds like **ఎమ్**\r\nN sounds like **ఎన్**\r\n\r\nNext:\r\n\r\nO, P, Q, R, S, T\r\nO sounds like **ఓ**\r\nP sounds like **పే**\r\nQ sounds like **కూ**\r\nR sounds like **ఎర్**\r\nS sounds like **ఎస్**\r\nT sounds like **టే**\r\n\r\nNext:\r\n\r\nU, V, W, X, Y, Z\r\nU sounds like **ఊ**\r\nV sounds like **ఫౌ**\r\nW sounds like **వే**\r\nX sounds like **ఇక్స్**\r\nY sounds like **యిప్సిలాన్**\r\nZ sounds like **త్సెట్**\r\n\r\nGerman లో extra letters కూడా ఉన్నాయి:\r\n\r\nÄ, Ö, Ü, ß\r\n\r\n**Ä** is called A-Umlaut.\r\n**Ö** is called O-Umlaut.\r\n**Ü** is called U-Umlaut.\r\n**ß** is called Eszett.\r\n\r\nఇవి German లో చాలా common.\r\n\r\nExamples:\r\n\r\n**Mädchen** లో ä ఉంది.\r\n**Jörg** లో ö ఉంది.\r\n**Grüße** లో ü ఉంది.\r\n**Straße** లో ß ఉంటుంది.\r\n\r\nWhy is alphabet important?\r\n\r\nBecause German official life లో spelling చాలా important. Name, address, license plate, email, document number అన్నీ spell చేయాలి. మీరు alphabet తెలియకపోతే simple call కూడా difficult అవుతుంది.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, English alphabet pronunciation తో German letters చెప్పడం.\r\n\r\nExample, German W ని English “double u” లాగా చెప్పకూడదు. German లో **W** is **వే**.\r\n\r\nGerman V ని English “vee” లాగా చెప్పకూడదు. German లో **V** is **ఫౌ**.\r\n\r\nSecond mistake, Z ని “జెడ్” అని చెప్పడం. German లో Z is **త్సెట్**.\r\n\r\nThird mistake, umlaut ignore చేయడం. **a** and **ä** same కాదు. **o** and **ö** same కాదు. **u** and **ü** same కాదు.\r\n\r\nLesson 1 connection:\r\n\r\nLesson 1 లో మనం **Mein Name ist...** నేర్చుకున్నాం. Lesson 4 లో అదే name ని spell చేయడం నేర్చుకుంటున్నాం.\r\n\r\nExample:\r\n\r\n**Mein Name ist Jeremiah.**\r\n\r\nNow someone asks:\r\n\r\n**Buchstabieren Sie bitte.**\r\n\r\nMeaning:\r\n\r\nPlease spell it.\r\n\r\nYou say:\r\n\r\nJ E R E M I A H\r\n\r\nGerman alphabet sounds తో slowly spell చేయాలి.\r\n\r\nNow second concept: **Wie ist die Autonummer?**\r\n\r\nMeaning:\r\n\r\nWhat is the car number?\r\n\r\n**die Autonummer** means car number or license plate number.\r\n\r\nPage లో car number plates ఉన్నాయి. Like:\r\n\r\nBAD EN 9999\r\nB MW 179\r\nTÜ PD 34\r\nHAL FS 28\r\nHH MM 616\r\nLÖ HI 43\r\nU FO 88\r\n\r\nGermany లో car number plates letters and numbers కలిపి ఉంటాయి. మీరు phone లో road assistance కి call చేస్తే, car number చెప్పాలి.\r\n\r\nDialog:\r\n\r\n**Mein Auto ist kaputt.**\r\n\r\nMeaning:\r\n\r\nMy car is broken.\r\n\r\n**Wie ist die Nummer, bitte?**\r\n\r\nMeaning:\r\n\r\nWhat is the number, please?\r\n\r\n**HAL FS 28. Es ist ein Toyota.**\r\n\r\nMeaning:\r\n\r\nHAL FS 28. It is a Toyota.\r\n\r\n**Der ADAC kommt gleich.**\r\n\r\nMeaning:\r\n\r\nThe ADAC is coming soon.\r\n\r\n**Danke. Ich warte.**\r\n\r\nMeaning:\r\n\r\nThank you. I am waiting.\r\n\r\nADAC అంటే Germany లో automobile club. Road assistance కోసం చాలా famous.\r\n\r\nImportant words:\r\n\r\n**mein Auto** = my car\r\n**kaputt** = broken\r\n**die Nummer** = number\r\n**bitte** = please\r\n**der Toyota** = Toyota\r\n**kommt gleich** = comes soon\r\n**Ich warte** = I am waiting\r\n\r\nWhy is this important?\r\n\r\nEmergency or practical situationsలో German మాట్లాడాలి. Car breakdown, taxi booking, police, hotel parking, insurance call, ఇవన్నీ number plate spelling మీద depend అవుతాయి.\r\n\r\nReal-life examples:\r\n\r\nExample 1:\r\n\r\n**Mein Auto ist kaputt.**\r\nMy car is broken.\r\n\r\n**Wie ist die Nummer, bitte?**\r\nWhat is the number, please?\r\n\r\n**B MW 179.**\r\nB MW 179.\r\n\r\nExample 2:\r\n\r\n**Es ist ein BMW.**\r\nIt is a BMW.\r\n\r\nExample 3:\r\n\r\n**Ich warte.**\r\nI am waiting.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, number plate లో letters German alphabet ప్రకారం చెప్పకపోవడం.\r\n\r\nSecond mistake, number order miss చేయడం.\r\n\r\nThird mistake, **mein Auto** లో **mein** use చేయాలి, **meine Auto** కాదు. Because **das Auto**, so **mein Auto**.\r\n\r\nLesson 3 connection:\r\n\r\nLesson 3 లో **mein Auto, dein Auto, ihr Auto** నేర్చుకున్నాం. ఇప్పుడు అదే **Mein Auto ist kaputt** అని real situation లో use చేస్తున్నాం.\r\n\r\nNow car brand words:\r\n\r\n**der VW**\r\n**der Volvo**\r\n**der Mercedes**\r\n**der Toyota**\r\n**der BMW**\r\n**der Ford**\r\n**der Porsche**\r\n**der Peugeot**\r\n\r\nGerman లో car brand names ముందు often **der** use చేస్తారు.\r\n\r\nExample:\r\n\r\n**Das ist ein Toyota.**\r\n\r\nThis is a Toyota.\r\n\r\n**Es ist ein BMW.**\r\n\r\nIt is a BMW.\r\n\r\nNow third concept: German words and sounds.\r\n\r\nLesson 4 లో words వినాలి, repeat చేయాలి, spell చేయాలి.\r\n\r\nFirst normal words:\r\n\r\n**Taxi**\r\n**ich**\r\n**zwei**\r\n**du**\r\n**Vergangenheit**\r\n**Polizei**\r\n**da**\r\n**zehn**\r\n**wo**\r\n**Jan**\r\n**Bahnhof**\r\n**ist**\r\n**Mama**\r\n**Krankenwagen**\r\n**jung**\r\n**Mann**\r\n**eins**\r\n\r\nThese are familiar words from previous lessons.\r\n\r\nNow special sounds.\r\n\r\nFirst: **ä**\r\n\r\nExamples:\r\n\r\n**Mädchen**\r\n**ergänzen**\r\n**Gepäck**\r\n\r\n**Mädchen** = girl\r\n**ergänzen** = to complete or fill in\r\n**Gepäck** = luggage\r\n\r\nRemember Lesson 3 లో **Ihr Gepäck ist komplett** నేర్చుకున్నాం. Here **Gepäck** లో ä sound ఉంది.\r\n\r\nNext: **ö**\r\n\r\nExamples:\r\n\r\n**Jörg**\r\n**hört**\r\n**schön**\r\n\r\n**Jörg** is a name.\r\n**hört** means hears or listens.\r\n**schön** means beautiful or nice.\r\n\r\nExample:\r\n\r\n**Das ist schön.**\r\n\r\nThat is nice.\r\n\r\nNext: **ü**\r\n\r\nExamples:\r\n\r\n**Grüße**\r\n**küssen**\r\n**fünf**\r\n\r\n**Grüße** = greetings\r\n**küssen** = to kiss\r\n**fünf** = five\r\n\r\nLesson 1 లో number 5 **fünf** నేర్చుకున్నాం. Now we notice it has **ü**.\r\n\r\nNow double vowel sounds.\r\n\r\n**au**\r\n\r\nExamples:\r\n\r\n**Auto**\r\n**Frau**\r\n\r\n**Auto** = car\r\n**Frau** = woman, Mrs.\r\n\r\n**äu**\r\n\r\nExamples:\r\n\r\n**träumen**\r\n**Verkäufer**\r\n\r\n**träumen** = to dream\r\n**Verkäufer** = seller\r\n\r\nLesson 2 లో Jan letter లో **Ich träume** వచ్చింది. Now pronunciation connect అవుతోంది.\r\n\r\n**eu**\r\n\r\nExamples:\r\n\r\n**neun**\r\n**neunzehn**\r\n\r\n**neun** = nine\r\n**neunzehn** = nineteen\r\n\r\n**ei**\r\n\r\nExamples:\r\n\r\n**zwei**\r\n**allein**\r\n\r\n**zwei** = two\r\n**allein** = alone\r\n\r\nImportant pronunciation tip:\r\n\r\nGerman **ei** sounds like **ఐ**.\r\nSo **zwei** sounds like **త్స్వై**, not “జ్వీ”.\r\n\r\n**ie**\r\n\r\nExamples:\r\n\r\n**liebe**\r\n**Briefe**\r\n\r\nGerman **ie** sounds like long **ఈ**.\r\n\r\n**liebe** sounds like **లీబె**.\r\n**Briefe** sounds like **బ్రీఫె**.\r\n\r\nCommon mistake:\r\n\r\n**ei** and **ie** confuse అవుతాయి.\r\n\r\n**ei** sounds like “eye.”\r\n**ie** sounds like “ee.”\r\n\r\nExamples:\r\n\r\n**zwei** has **ei**, sounds like “tsvai.”\r\n**liebe** has **ie**, sounds like “lee-be.”\r\n\r\nThis is very important for speaking and listening.\r\n\r\nLesson 2 connection:\r\n\r\nLesson 2 లో **Ich liebe dich** నేర్చుకున్నాం. Now we learn **liebe** pronunciation. It is **లీబె**, not **లైబె**.\r\n\r\nNow fourth concept: **Namen buchstabieren**\r\n\r\nMeaning:\r\n\r\nSpelling names.\r\n\r\nGerman sentence:\r\n\r\n**Buchstabieren Sie bitte Ihren Namen.**\r\n\r\nMeaning:\r\n\r\nPlease spell your name.\r\n\r\n**buchstabieren** = to spell\r\n**Ihr Name** = your name, formal\r\n**bitte** = please\r\n\r\nExample from lesson:\r\n\r\n**Ich heiße Claudia Mauro.**\r\n\r\nMy name is Claudia Mauro.\r\n\r\n**Mein Vorname ist Claudia.**\r\n\r\nMy first name is Claudia.\r\n\r\n**Mein Familienname ist Mauro.**\r\n\r\nMy family name is Mauro.\r\n\r\nThen spelling:\r\n\r\n**C L A U D I A**\r\n**M A U R O**\r\n\r\nImportant words:\r\n\r\n**der Vorname** = first name\r\n**der Familienname** = family name\r\n**der Nachname** = last name\r\n\r\nIn many German forms, you may see **Vorname** and **Nachname** or **Familienname**.\r\n\r\nExample for you:\r\n\r\n**Ich heiße Jeremiah Elior.**\r\n\r\n**Mein Vorname ist Jeremiah.**\r\n\r\n**Mein Familienname ist Elior.**\r\n\r\nIf someone asks spelling:\r\n\r\n**Buchstabieren Sie bitte Ihren Namen.**\r\n\r\nYou can say:\r\n\r\n**J E R E M I A H.**\r\n\r\nOr:\r\n\r\n**Mein Vorname ist Jeremiah. J E R E M I A H.**\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, Vorname and Familienname confuse అవడం.\r\n\r\n**Vorname** = first name.\r\n**Familienname/Nachname** = last name.\r\n\r\nSecond mistake, spelling too fast. German official calls లో slowly spell చేయాలి.\r\n\r\nThird mistake, English letter sound use చేయడం. Better German letter pronunciation practice చేయాలి.\r\n\r\nLesson 1 connection:\r\n\r\nLesson 1 లో మనం **Mein Vorname ist... Mein Nachname ist...** నేర్చుకున్నాం. Lesson 4 లో same topic deeper speaking practice.\r\n\r\nNow fifth concept: **Wie geht es Ihnen? Wie geht es dir?**\r\n\r\nMeaning:\r\n\r\nHow are you?\r\n\r\nGerman లో formal and informal versions ఉన్నాయి.\r\n\r\nFormal:\r\n\r\n**Wie geht es Ihnen?**\r\n\r\nInformal:\r\n\r\n**Wie geht es dir?**\r\n\r\nLesson 1 లో **Sie** and **du** difference నేర్చుకున్నాం.\r\n\r\n**Ihnen** belongs to formal **Sie**.\r\n**dir** belongs to informal **du**.\r\n\r\nFormal conversation:\r\n\r\n**Guten Tag, Herr Müller.**\r\n\r\nGood day, Mr. Müller.\r\n\r\n**Guten Tag, Frau Meier. Wie geht es Ihnen?**\r\n\r\nGood day, Mrs. Meier. How are you?\r\n\r\n**Danke, es geht mir gut. Und Ihnen?**\r\n\r\nThank you, I am fine. And you?\r\n\r\n**Danke, auch gut.**\r\n\r\nThank you, also good.\r\n\r\nInformal conversation:\r\n\r\n**Hallo, Corinna.**\r\n\r\nHi, Corinna.\r\n\r\n**Hallo, Klaus. Wie geht es dir?**\r\n\r\nHi, Klaus. How are you?\r\n\r\n**Danke gut, und dir?**\r\n\r\nThanks, good. And you?\r\n\r\n**Es geht.**\r\n\r\nIt is okay.\r\n\r\nNow meanings:\r\n\r\n**Wie geht es Ihnen?** = How are you? Formal.\r\n**Wie geht es dir?** = How are you? Informal.\r\n**Es geht mir gut.** = I am fine.\r\n**Danke gut.** = Thanks, good.\r\n**Auch gut.** = Also good.\r\n**Es geht.** = It is okay, not bad, so-so.\r\n\r\nWhy important?\r\n\r\nEvery German conversation often starts with greeting and “How are you?” This helps you sound polite and natural.\r\n\r\nReal-life examples:\r\n\r\nOffice:\r\n\r\n**Guten Tag, Frau Schneider. Wie geht es Ihnen?**\r\n\r\nFriend:\r\n\r\n**Hallo, Anna. Wie geht es dir?**\r\n\r\nNeighbor:\r\n\r\nIf formal:\r\n\r\n**Guten Tag. Wie geht es Ihnen?**\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, using **dir** with formal people.\r\n\r\nWrong with officer:\r\n\r\n**Wie geht es dir?**\r\n\r\nBetter:\r\n\r\n**Wie geht es Ihnen?**\r\n\r\nSecond mistake, answering only **gut** is okay, but better sentence:\r\n\r\n**Danke, es geht mir gut.**\r\n\r\nThird mistake, forgetting **Und Ihnen?** or **Und dir?**\r\n\r\nIf someone asks how are you, polite answer includes asking back.\r\n\r\nFormal:\r\n\r\n**Und Ihnen?**\r\n\r\nInformal:\r\n\r\n**Und dir?**\r\n\r\nLesson 1 and 2 connection:\r\n\r\nLesson 1 greetings now become full greeting conversations. Lesson 2 **du** questions now become real friendly speaking.\r\n\r\nNow sixth concept: **Wo bist du? Wo sind Sie?**\r\n\r\nMeaning:\r\n\r\nWhere are you?\r\n\r\nInformal:\r\n\r\n**Wo bist du?**\r\n\r\nFormal:\r\n\r\n**Wo sind Sie?**\r\n\r\nExample conversation informal:\r\n\r\n**Noll. Guten Tag.**\r\n\r\nNoll speaking. Good day.\r\n\r\n**Hallo, Jörg. Hier ist Claudia.**\r\n\r\nHello, Jörg. This is Claudia.\r\n\r\n**Hallo, Claudia. Wo bist du?**\r\n\r\nHello, Claudia. Where are you?\r\n\r\n**In München. Ich bin in München.**\r\n\r\nIn Munich. I am in Munich.\r\n\r\n**Wann kommst du?**\r\n\r\nWhen are you coming?\r\n\r\n**Morgen.**\r\n\r\nTomorrow.\r\n\r\nFormal conversation:\r\n\r\n**Nolte, guten Tag.**\r\n\r\nNolte speaking. Good day.\r\n\r\n**Guten Tag, Herr Nolte. Hier ist Soprana.**\r\n\r\nGood day, Mr. Nolte. This is Soprana.\r\n\r\n**Guten Tag, Frau Soprana. Wo sind Sie?**\r\n\r\nGood day, Mrs. Soprana. Where are you?\r\n\r\n**In London. Ich bin in London.**\r\n\r\nIn London. I am in London.\r\n\r\n**Arbeiten Sie?**\r\n\r\nAre you working?\r\n\r\n**Nein, ich arbeite nicht.**\r\n\r\nNo, I am not working.\r\n\r\nImportant phrases:\r\n\r\n**Hier ist Claudia.**\r\nThis is Claudia.\r\n\r\nOn phone, German often says **Hier ist...**\r\n\r\nMeaning:\r\n\r\nThis is...\r\n\r\n**Ich bin in München.**\r\nI am in Munich.\r\n\r\n**Ich bin in London.**\r\nI am in London.\r\n\r\n**Wann kommst du?**\r\nWhen are you coming?\r\n\r\n**Morgen.**\r\nTomorrow.\r\n\r\n**Arbeiten Sie?**\r\nAre you working? Formal.\r\n\r\n**Ich arbeite nicht.**\r\nI am not working.\r\n\r\nWhy important?\r\n\r\nPhone conversation is daily life. You may need to say where you are, when you come, whether you are working.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, **Wo bist du?** and **Wo sind Sie?** mix చేయడం.\r\n\r\n**du** goes with **bist**.\r\n**Sie** goes with **sind**.\r\n\r\nWrong:\r\n\r\n**Wo bist Sie?**\r\n\r\nCorrect:\r\n\r\n**Wo sind Sie?**\r\n\r\nWrong:\r\n\r\n**Wo sind du?**\r\n\r\nCorrect:\r\n\r\n**Wo bist du?**\r\n\r\nSecond mistake, phone opening.\r\n\r\nEnglish: This is Claudia.\r\nGerman: **Hier ist Claudia.**\r\n\r\nThird mistake, **nicht** placement.\r\n\r\n**Ich arbeite nicht.** Correct.\r\n\r\nLesson 3 connection:\r\n\r\nLesson 3 లో phone conversations వినాం. Lesson 4 లో same phone style speaking practice చేస్తున్నాం.\r\n\r\nNow seventh concept: **Zahlen von 10 bis 100**\r\n\r\nMeaning:\r\n\r\nNumbers from 10 to 100.\r\n\r\nLesson 1 లో 1 to 10 నేర్చుకున్నాం.\r\n\r\nNow we continue.\r\n\r\n10 = **zehn**\r\n11 = **elf**\r\n12 = **zwölf**\r\n13 = **dreizehn**\r\n14 = **vierzehn**\r\n15 = **fünfzehn**\r\n16 = **sechzehn**\r\n17 = **siebzehn**\r\n18 = **achtzehn**\r\n19 = **neunzehn**\r\n\r\nNow tens:\r\n\r\n20 = **zwanzig**\r\n30 = **dreißig**\r\n40 = **vierzig**\r\n50 = **fünfzig**\r\n60 = **sechzig**\r\n70 = **siebzig**\r\n80 = **achtzig**\r\n90 = **neunzig**\r\n100 = **hundert**\r\n\r\nVery important: German numbers from 21 onward are reversed compared to English.\r\n\r\n21 is not twenty-one directly. German says:\r\n\r\n**einundzwanzig**\r\n\r\nLiterally: one and twenty.\r\n\r\n22:\r\n\r\n**zweiundzwanzig**\r\n\r\nTwo and twenty.\r\n\r\n23:\r\n\r\n**dreiundzwanzig**\r\n\r\nThree and twenty.\r\n\r\n24:\r\n\r\n**vierundzwanzig**\r\n\r\nFour and twenty.\r\n\r\n25:\r\n\r\n**fünfundzwanzig**\r\n\r\nFive and twenty.\r\n\r\n26:\r\n\r\n**sechsundzwanzig**\r\n\r\nSix and twenty.\r\n\r\n27:\r\n\r\n**siebenundzwanzig**\r\n\r\nSeven and twenty.\r\n\r\n28:\r\n\r\n**achtundzwanzig**\r\n\r\nEight and twenty.\r\n\r\n29:\r\n\r\n**neunundzwanzig**\r\n\r\nNine and twenty.\r\n\r\nNow 31:\r\n\r\n**einunddreißig**\r\n\r\nOne and thirty.\r\n\r\n32:\r\n\r\n**zweiunddreißig**\r\n\r\nTwo and thirty.\r\n\r\n33:\r\n\r\n**dreiunddreißig**\r\n\r\nThree and thirty.\r\n\r\nWhy important?\r\n\r\nAge, price, bus number, platform, phone number, house number, date, all need numbers.\r\n\r\nReal-life examples:\r\n\r\n**Ich bin 24 Jahre alt.**\r\nI am 24 years old.\r\n\r\n**Mein Auto ist 14 Jahre alt.**\r\nMy car is 14 years old.\r\n\r\n**Mein Großvater ist 72.**\r\nMy grandfather is 72.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, 13 and 30 confuse అవడం.\r\n\r\n13 = **dreizehn**\r\n30 = **dreißig**\r\n\r\n14 = **vierzehn**\r\n40 = **vierzig**\r\n\r\n15 = **fünfzehn**\r\n50 = **fünfzig**\r\n\r\n16 = **sechzehn**\r\n60 = **sechzig**\r\n\r\n17 = **siebzehn**\r\n70 = **siebzig**\r\n\r\n18 = **achtzehn**\r\n80 = **achtzig**\r\n\r\n19 = **neunzehn**\r\n90 = **neunzig**\r\n\r\nSecond mistake, 21 English order లో చెప్పడం.\r\n\r\nWrong thinking:\r\n\r\ntwenty-one = zwanzig eins\r\n\r\nCorrect German:\r\n\r\n**einundzwanzig**\r\n\r\nThird mistake, **sechzehn** and **sechzig** pronunciation.\r\n\r\n16 = **sechzehn**\r\n60 = **sechzig**\r\n\r\nThey sound different. Practice slowly.\r\n\r\nLesson 1 connection:\r\n\r\nLesson 1 numbers 1 to 10 were base. Lesson 4 builds 10 to 100 using that base.\r\n\r\nNow eighth concept: **Wie alt sind die Personen?**\r\n\r\nMeaning:\r\n\r\nHow old are the people?\r\n\r\nImportant question:\r\n\r\n**Wie alt bist du?**\r\n\r\nHow old are you? Informal.\r\n\r\nFormal:\r\n\r\n**Wie alt sind Sie?**\r\n\r\nHow old are you? Formal.\r\n\r\nAnswer:\r\n\r\n**Ich bin 16 Jahre alt.**\r\n\r\nI am 16 years old.\r\n\r\nOr short:\r\n\r\n**Ich bin 16.**\r\n\r\nI am 16.\r\n\r\nFamily examples:\r\n\r\n**Meine Großmutter ist 68 Jahre alt.**\r\n\r\nMy grandmother is 68 years old.\r\n\r\n**Mein Großvater ist 72 Jahre alt.**\r\n\r\nMy grandfather is 72 years old.\r\n\r\n**Mein Vater ist 45 Jahre alt.**\r\n\r\nMy father is 45 years old.\r\n\r\n**Mein Hund ist 5 Jahre alt.**\r\n\r\nMy dog is 5 years old.\r\n\r\nImportant words:\r\n\r\n**Jahre alt** = years old\r\n**mein Vater** = my father\r\n**meine Mutter** = my mother\r\n**mein Großvater** = my grandfather\r\n**meine Großmutter** = my grandmother\r\n**mein Hund** = my dog\r\n\r\nWhy important?\r\n\r\nAge is common in introductions, family talks, forms, school, doctor, child-related conversation.\r\n\r\nReal-life examples:\r\n\r\n**Meine Tochter ist 4 Jahre alt.**\r\n\r\nMy daughter is 4 years old.\r\n\r\n**Mein Sohn ist zehn.**\r\n\r\nMy son is ten.\r\n\r\n**Meine Mutter ist 60 Jahre alt.**\r\n\r\nMy mother is 60 years old.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, English style “I have 30 years” use చేయడం. German లో:\r\n\r\n**Ich bin 30 Jahre alt.**\r\n\r\nNot:\r\n\r\n**Ich habe 30 Jahre.**\r\n\r\nSecond mistake, plural **Jahre** forget చేయడం.\r\n\r\nFor 1:\r\n\r\n**ein Jahr alt**\r\n\r\nFor more than 1:\r\n\r\n**zwei Jahre alt, zehn Jahre alt**\r\n\r\nThird mistake, **alt** forget చేయడం. Short answer **Ich bin 30** is okay, but full sentence:\r\n\r\n**Ich bin 30 Jahre alt.**\r\n\r\nLesson 2 connection:\r\n\r\nLesson 2 లో **Ich bin glücklich, du bist glücklich** నేర్చుకున్నాం. ఇప్పుడు **Ich bin 30 Jahre alt** అని same **bin** use చేస్తున్నాం.\r\n\r\nNow ninth concept: **Das ist meine Familie**\r\n\r\nMeaning:\r\n\r\nThis is my family.\r\n\r\nThis section is very practical. German లో family గురించి ఎలా చెప్పాలో నేర్పిస్తుంది.\r\n\r\nExample 1:\r\n\r\n**Das ist mein Bruder.**\r\n\r\nThis is my brother.\r\n\r\n**Er ist 24 Jahre alt.**\r\n\r\nHe is 24 years old.\r\n\r\n**Sein Name ist Uwe.**\r\n\r\nHis name is Uwe.\r\n\r\n**Der Hund von Uwe heißt Bello.**\r\n\r\nUwe’s dog is called Bello.\r\n\r\nImportant words:\r\n\r\n**mein Bruder** = my brother\r\n**sein Name** = his name\r\n**der Hund** = the dog\r\n**heißt** = is called\r\n\r\nExample 2:\r\n\r\n**Das ist meine Mutter.**\r\n\r\nThis is my mother.\r\n\r\n**Sie wohnt in Berlin.**\r\n\r\nShe lives in Berlin.\r\n\r\n**Ihr Auto ist 14 Jahre alt.**\r\n\r\nHer car is 14 years old.\r\n\r\nImportant:\r\n\r\nMother is female, so her = **ihr**.\r\nAuto is **das Auto**, so **ihr Auto**.\r\n\r\nExample 3:\r\n\r\n**Das sind meine Großeltern.**\r\n\r\nThese are my grandparents.\r\n\r\n**Mein Großvater heißt Kurt und ist 72 Jahre alt.**\r\n\r\nMy grandfather is called Kurt and is 72 years old.\r\n\r\n**Meine Großmutter ist 68 und heißt Anna.**\r\n\r\nMy grandmother is 68 and is called Anna.\r\n\r\nExample 4:\r\n\r\n**Meine Schwester spielt Klavier.**\r\n\r\nMy sister plays piano.\r\n\r\n**Sie heißt Emma.**\r\n\r\nHer name is Emma.\r\n\r\n**Ihre Tochter ist 2 Jahre alt.**\r\n\r\nHer daughter is 2 years old.\r\n\r\nFamily vocabulary:\r\n\r\n**mein Vater** = my father\r\n**meine Mutter** = my mother\r\n**mein Bruder** = my brother\r\n**meine Schwester** = my sister\r\n**mein Mann** = my husband\r\n**meine Frau** = my wife\r\n**mein Sohn** = my son\r\n**meine Tochter** = my daughter\r\n**meine Eltern** = my parents\r\n**meine Großeltern** = my grandparents\r\n**meine Geschwister** = my siblings\r\n\r\nNotice the pattern again.\r\n\r\nMasculine:\r\n\r\n**mein Vater**\r\n**mein Bruder**\r\n**mein Mann**\r\n**mein Sohn**\r\n\r\nFeminine:\r\n\r\n**meine Mutter**\r\n**meine Schwester**\r\n**meine Frau**\r\n**meine Tochter**\r\n\r\nPlural:\r\n\r\n**meine Eltern**\r\n**meine Großeltern**\r\n**meine Geschwister**\r\n\r\nWhy important?\r\n\r\nFamily introduction is one of the first topics in any language. You may use it in German class, school, Kita, immigration forms, casual conversation, church, friends, neighbors.\r\n\r\nReal-life example:\r\n\r\n**Das ist meine Familie.**\r\n\r\nThis is my family.\r\n\r\n**Meine Frau heißt Divya.**\r\n\r\nMy wife is called Divya.\r\n\r\n**Meine Tochter ist 4 Jahre alt.**\r\n\r\nMy daughter is 4 years old.\r\n\r\n**Wir wohnen in Berlin.**\r\n\r\nWe live in Berlin.\r\n\r\nAnother example:\r\n\r\n**Das ist mein Bruder. Er wohnt in Hamburg.**\r\n\r\nThis is my brother. He lives in Hamburg.\r\n\r\nAnother:\r\n\r\n**Meine Eltern wohnen in Indien.**\r\n\r\nMy parents live in India.\r\n\r\nCommon mistakes:\r\n\r\nFirst mistake, **mein** and **meine** confuse అవడం.\r\n\r\nCorrect:\r\n\r\n**mein Vater**\r\n**meine Mutter**\r\n\r\nWrong:\r\n\r\n**meine Vater**\r\n**mein Mutter**\r\n\r\nSecond mistake, plural with **mein**.\r\n\r\nWrong:\r\n\r\n**mein Eltern**\r\n\r\nCorrect:\r\n\r\n**meine Eltern**\r\n\r\nThird mistake, age sentence.\r\n\r\nCorrect:\r\n\r\n**Meine Tochter ist 4 Jahre alt.**\r\n\r\nNot:\r\n\r\n**Meine Tochter hat 4 Jahre.**\r\n\r\nLesson 3 connection:\r\n\r\nLesson 3 లో **mein Sohn, meine Tochter, meine Kinder** నేర్చుకున్నాం. Lesson 4 లో family introduction లో వాటిని use చేస్తున్నాం.\r\n\r\nNow let’s create one full family introduction practice.\r\n\r\nListen and repeat:\r\n\r\n**Das ist meine Familie.**\r\n\r\nThis is my family.\r\n\r\n**Das ist meine Frau. Sie heißt Divya.**\r\n\r\nThis is my wife. Her name is Divya.\r\n\r\n**Das ist meine Tochter. Sie ist 4 Jahre alt.**\r\n\r\nThis is my daughter. She is 4 years old.\r\n\r\n**Wir wohnen in Berlin.**\r\n\r\nWe live in Berlin.\r\n\r\n**Meine Eltern wohnen in Indien.**\r\n\r\nMy parents live in India.\r\n\r\n**Mein Vater heißt...**\r\n\r\nMy father is called...\r\n\r\n**Meine Mutter heißt...**\r\n\r\nMy mother is called...\r\n\r\nYou can replace names and ages with your own family.\r\n\r\nNow let’s connect all lesson 4 concepts in one real-life story.\r\n\r\nImagine you are in Germany.\r\n\r\nFirst, you call ADAC because your car is broken.\r\n\r\n**Mein Auto ist kaputt.**\r\n\r\nThey ask:\r\n\r\n**Wie ist die Nummer, bitte?**\r\n\r\nYou spell the number using German alphabet.\r\n\r\nThen they ask your name:\r\n\r\n**Buchstabieren Sie bitte Ihren Namen.**\r\n\r\nYou say:\r\n\r\n**Mein Vorname ist Jeremiah. J E R E M I A H.**\r\n\r\nThen you meet someone formally:\r\n\r\n**Guten Tag. Wie geht es Ihnen?**\r\n\r\nThey say:\r\n\r\n**Danke, es geht mir gut. Und Ihnen?**\r\n\r\nThen your friend calls:\r\n\r\n**Wo bist du?**\r\n\r\nYou say:\r\n\r\n**Ich bin in München. Ich komme morgen.**\r\n\r\nThen someone asks about your family:\r\n\r\n**Das ist meine Familie. Meine Tochter ist 4 Jahre alt. Wir wohnen in Berlin.**\r\n\r\nSee, Lesson 4 is very practical. Alphabet, numbers, names, family, phone calls. These are daily German survival skills.\r\n\r\nNow chapter summary.\r\n\r\nIn Lesson 4, we learned:\r\n\r\nGerman alphabet and special letters:\r\n\r\n**Ä, Ö, Ü, ß**\r\n\r\nSpelling names:\r\n\r\n**Buchstabieren Sie bitte Ihren Namen.**\r\n\r\nFirst name and family name:\r\n\r\n**Mein Vorname ist...**\r\n\r\n**Mein Familienname ist...**\r\n\r\nCar problem:\r\n\r\n**Mein Auto ist kaputt.**\r\n\r\n**Wie ist die Nummer, bitte?**\r\n\r\n**Der ADAC kommt gleich.**\r\n\r\nHow are you formal:\r\n\r\n**Wie geht es Ihnen?**\r\n\r\nInformal:\r\n\r\n**Wie geht es dir?**\r\n\r\nAnswers:\r\n\r\n**Danke, es geht mir gut.**\r\n\r\n**Danke, auch gut.**\r\n\r\n**Es geht.**\r\n\r\nPhone location:\r\n\r\n**Wo bist du?**\r\n\r\n**Wo sind Sie?**\r\n\r\n**Ich bin in München.**\r\n\r\n**Ich bin in London.**\r\n\r\nNumbers 10 to 100:\r\n\r\n**zehn, elf, zwölf, dreizehn, zwanzig, dreißig, vierzig, fünfzig, sechzig, siebzig, achtzig, neunzig, hundert**\r\n\r\nAge:\r\n\r\n**Ich bin 24 Jahre alt.**\r\n\r\nFamily:\r\n\r\n**Das ist meine Familie.**\r\n\r\n**Das ist mein Bruder.**\r\n\r\n**Das ist meine Mutter.**\r\n\r\n**Das sind meine Großeltern.**\r\n\r\n**Meine Schwester spielt Klavier.**\r\n\r\nNow practical analogy.\r\n\r\nThink of Lesson 4 like learning how to introduce your identity in Germany.\r\n\r\nAlphabet is your spelling tool.\r\n\r\nNumbers are your age, phone, car, and document tool.\r\n\r\nGreetings are your social tool.\r\n\r\nFamily words are your personal life tool.\r\n\r\nPhone phrases are your daily communication tool.\r\n\r\nSo this lesson is like preparing your German ID card. It helps you say who you are, where you are, how you are, how old you are, and who is in your family.\r\n\r\nNow quiz time.\r\n\r\nQuestion 1: German లో “Please spell your name” ఎలా చెప్తారు?\r\n\r\nQuestion 2: **Mein Auto ist kaputt** meaning ఏమిటి?\r\n\r\nQuestion 3: **Wie ist die Nummer, bitte?** meaning ఏమిటి?\r\n\r\nQuestion 4: Formal German లో “How are you?” ఎలా అడుగుతారు?\r\n\r\nQuestion 5: Informal German లో “How are you?” ఎలా అడుగుతారు?\r\n\r\nQuestion 6: **Wo bist du?** meaning ఏమిటి?\r\n\r\nQuestion 7: 21 German లో ఎలా చెప్తారు?\r\n\r\nQuestion 8: **Ich bin 30 Jahre alt** meaning ఏమిటి?\r\n\r\nQuestion 9: **Das ist meine Mutter** meaning ఏమిటి?\r\n\r\nQuestion 10: **Meine Großeltern wohnen in Berlin** meaning ఏమిటి?\r\n\r\nAnswers:\r\n\r\n1. **Buchstabieren Sie bitte Ihren Namen.**\r\n2. My car is broken.\r\n3. What is the number, please?\r\n4. **Wie geht es Ihnen?**\r\n5. **Wie geht es dir?**\r\n6. Where are you? Informal.\r\n7. **einundzwanzig**\r\n8. I am 30 years old.\r\n9. This is my mother.\r\n10. My grandparents live in Berlin.\r\n\r\nOutro:\r\n\r\nFriends, Lesson 4 లో మనం speaking కి చాలా strong foundation నేర్చుకున్నాం.\r\n\r\nRepeat these daily:\r\n\r\n**Buchstabieren Sie bitte Ihren Namen.**\r\n\r\n**Mein Auto ist kaputt.**\r\n\r\n**Wie geht es Ihnen?**\r\n\r\n**Wie geht es dir?**\r\n\r\n**Wo bist du?**\r\n\r\n**Ich bin in Berlin.**\r\n\r\n**Ich bin 30 Jahre alt.**\r\n\r\n**Das ist meine Familie.**\r\n\r\nGerman speaking practice లో speed important కాదు. Clarity important. Slowly చెప్పండి. Correctగా repeat చేయండి. Daily small sentences use చేయండి.\r\n\r\nDanke schön. Auf Wiedersehen. See you in the next lesson.', 'https://silver-llama-257051.hostingersite.com/uploads/audio/1781100631-ai-chapter4.m4a', 1, '2026-06-21 23:44:29', '2026-06-21 23:44:29'),
(9, 1, 'ta', '', '', '', 0, '2026-06-25 16:40:44', '2026-06-25 16:40:44'),
(10, 1, 'kn', 'ಜನರು ಮತ್ತು ಪ್ರಯಾಣ', 'Podcast Title: German Kannada Lesson 1, Menschen und Reisen\r\n\r\n(Intro music, soft and calm)\r\n\r\nನಮಸ್ಕಾರ ಸ್ನೇಹಿತರೆ. ನಮ್ಮ ಜರ್ಮನ್ ಕಲಿಯುವ ಪಾಡ್‌ಕಾಸ್ಟ್‌ಗೆ ಸ್ವಾಗತ.\r\n\r\nಇಂದು ನಾವು ಜರ್ಮನ್‌ನಲ್ಲಿ (German) ಬಹಳ ಬೇಸಿಕ್ (basic) ಆದರೆ ಬಹಳ ಉಪಯೋಗವಾಗುವ (useful) ಚಾಪ್ಟರ್ ಕಲಿಯಲಿದ್ದೇವೆ. ಚಾಪ್ಟರ್ ಹೆಸರು Menschen und Reisen. ಅಂದರೆ ಕನ್ನಡದಲ್ಲಿ ಜನರು ಮತ್ತು ಪ್ರಯಾಣ.\r\n\r\nಇದು ಬಿಗಿನರ್ ಲೆವೆಲ್ (beginner level) ಚಾಪ್ಟರ್. ಆದರೆ ಬಹಳ important. ಏಕೆಂದರೆ, ಜರ್ಮನಿಯಲ್ಲಿ ನಾವು ಹೊರಗೆ ಹೋದಾಗ, ಸ್ಟೇಷನ್‌ನಲ್ಲಿ, ಏರ್‌ಪೋರ್ಟ್‌ನಲ್ಲಿ, ಹೋಟೆಲ್‌ನಲ್ಲಿ, ಬಸ್ ಸ್ಟಾಪ್ ಹತ್ತಿರ, ಇನ್ಫಾರ್ಮೇಶನ್ ಕೌಂಟರ್ ಹತ್ತಿರ ಅಥವಾ ಅಪಾಯಿಂಟ್‌ಮೆಂಟ್‌ಗೆ ಹೋದಾಗ, ಬೇಸಿಕ್ ಜರ್ಮನ್ ಪದಗಳು ಬಹಳ ಅವಶ್ಯಕವಾಗುತ್ತವೆ.\r\n\r\nಈ ಪಾಠದಲ್ಲಿ (Lesson) ನಾವು ಕಲಿಯಲಿರುವುದು:\r\nಮೊದಲನೆಯದಾಗಿ ಅನೌನ್ಸ್‌ಮೆಂಟ್‌ಗಳನ್ನು (announcements) ಹೇಗೆ ಕೇಳಿಸಿಕೊಳ್ಳಬೇಕು.\r\n\r\nನಂತರ ನಮ್ಮ ಹೆಸರನ್ನು ಹೇಗೆ ಹೇಳಬೇಕು.\r\n\r\nಇತರರ ಹೆಸರನ್ನು ಹೇಗೆ ಕೇಳಬೇಕು.\r\n\r\nNumbers 1 ರಿಂದ 10.\r\n\r\nದೈನಂದಿನ ಪ್ರಯಾಣದ ಪದಗಳು (Daily travel words).\r\n\r\nಜರ್ಮನ್ ಆರ್ಟಿಕಲ್ಸ್ (German articles), ಅಂದರೆ der, die, das.\r\n\r\nಕೊನೆಯದಾಗಿ ಸಿಂಗುಲರ್ (singular) ಮತ್ತು ಪ್ಲೂರಲ್ (plural).\r\n\r\nSo relax. ನಿಧಾನವಾಗಿ ಕೇಳಿ. Repeat ಮಾಡಿ. ಜರ್ಮನ್ ಮೊದಲು ಕಷ್ಟ ಅನಿಸಬಹುದು, ಆದರೆ ಹಂತ ಹಂತವಾಗಿ (step by step) ಹೋದರೆ ಬಹಳ ಸುಲಭವಾಗುತ್ತದೆ (easy).\r\n\r\nLet’s start.\r\n\r\nChapter Theme: Menschen und Reisen\r\nMenschen ಅಂದರೆ people, ಜನರು.\r\n\r\nReisen ಅಂದರೆ travel, ಪ್ರಯಾಣ.\r\n\r\nಅಂದರೆ ಈ ಚಾಪ್ಟರ್‌ನಲ್ಲಿ ಸ್ಟೇಷನ್‌ನಲ್ಲಿ, ಟ್ಯಾಕ್ಸಿಯಲ್ಲಿ, ಟ್ರೈನ್‌ನಲ್ಲಿ, ಹೋಟೆಲ್ ಹತ್ತಿರ, ಇನ್ಫಾರ್ಮೇಶನ್ ಕೌಂಟರ್ ಹತ್ತಿರ ನಡೆಯುವ ಚಿಕ್ಕ ಸಂಭಾಷಣೆಗಳು (small conversations) ಇರುತ್ತವೆ.\r\n\r\nImagine ಮಾಡಿ. ನೀವು ಬರ್ಲಿನ್‌ನಲ್ಲಿ (Berlin) ಒಂದು ರೈಲ್ವೆ ಸ್ಟೇಷನ್‌ನಲ್ಲಿದ್ದೀರಾ. ನಿಮ್ಮ ಸುತ್ತಮುತ್ತ ಜನರು ನಡೆಯುತ್ತಿದ್ದಾರೆ. ಕೆಲವರು ಟ್ಯಾಕ್ಸಿಗಾಗಿ ನೋಡುತ್ತಿದ್ದಾರೆ. ಕೆಲವರು ಟ್ರೈನ್‌ಗಾಗಿ ಕಾಯುತ್ತಿದ್ದಾರೆ. ಇನ್ನೊಬ್ಬರು ಇನ್ಫಾರ್ಮೇಶನ್ ಕೌಂಟರ್ ಹತ್ತಿರ ಕೇಳುತ್ತಿದ್ದಾರೆ. ಸಡನ್ ಆಗಿ ಒಂದು announcement ಬರುತ್ತದೆ:\r\n\r\nFrau Beier bitte zur Information.\r\n\r\nಇದರ ಅರ್ಥ: Mrs. Beier, please come to the information desk. (ಶ್ರೀಮತಿ ಬೇಯರ್, ದಯವಿಟ್ಟು ಮಾಹಿತಿ ಕೇಂದ್ರಕ್ಕೆ ಬನ್ನಿ.)\r\n\r\nಇಲ್ಲಿರುವ ಮುಖ್ಯವಾದ ಪದಗಳು (Important words):\r\n\r\nFrau ಅಂದರೆ Mrs. ಅಥವಾ Ms. (ಶ್ರೀಮತಿ)\r\n\r\nHerr ಅಂದರೆ Mr. (ಶ್ರೀ)\r\n\r\nbitte ಅಂದರೆ please (ದಯವಿಟ್ಟು).\r\n\r\nzur Information ಅಂದರೆ ಇನ್ಫಾರ್ಮೇಶನ್ ಕೌಂಟರ್ ಹತ್ತಿರಕ್ಕೆ.\r\n\r\nಈಗ ಇನ್ನೊಂದು ವಾಕ್ಯ (sentence) ಕೇಳೋಣ:\r\n\r\nHerr Hans Meier bitte zur Information.\r\n\r\nಅಂದರೆ: Mr. Hans Meier, please come to the information counter.\r\n\r\nಸ್ನೇಹಿತರೆ, ಜರ್ಮನಿಯಲ್ಲಿ ಟ್ರೈನ್ ಸ್ಟೇಷನ್, ಏರ್‌ಪೋರ್ಟ್, ಆಸ್ಪತ್ರೆ, ಆಫೀಸ್ ಮುಂತಾದ ಸ್ಥಳಗಳಲ್ಲಿ announcements ಕಾಮನ್ (common). ಅದಕ್ಕಾಗಿಯೇ ನಿಮ್ಮ ಹೆಸರು ಅಥವಾ ಬೇರೆಯವರ ಹೆಸರು ಅನೌನ್ಸ್ ಮಾಡಿದರೆ ಅದನ್ನು ಗುರುತಿಸುವುದು ಬಹಳ important.\r\n\r\nಕಾಮನ್ ಆಗಿ ಮಾಡುವ ತಪ್ಪು (Common mistake) ಏನೆಂದರೆ, ಕಲಿಯುವವರು Frau ಮತ್ತು Herr ಮಧ್ಯೆ confuse ಆಗುತ್ತಾರೆ.\r\n\r\nಸಿಂಪಲ್ ರೂಲ್ (Simple rule) ನೆನಪಿಟ್ಟುಕೊಳ್ಳಿ:\r\n\r\nFrau - ಮಹಿಳೆಯರಿಗಾಗಿ (Female)\r\n\r\nHerr - ಪುರುಷರಿಗಾಗಿ (Male)\r\n\r\nಉದಾಹರಣೆ (Example):\r\n\r\nFrau Soprana = Mrs. Soprana.\r\n\r\nHerr Meier = Mr. Meier.\r\n\r\nಇನ್ನೊಂದು ತಪ್ಪು, ನಮಗೆ ಪೂರ್ತಿ ವಾಕ್ಯ ಅರ್ಥವಾಗುತ್ತಿಲ್ಲ ಎಂದು ನಾವು ಗಾಬರಿಯಾಗುತ್ತೇವೆ (panic). ಆದರೆ ಅದರ ಅವಶ್ಯಕತೆಯಿಲ್ಲ. ಮೊದಲು ನೀವು ಕೀವರ್ಡ್ಸ್ (keywords) ಹಿಡಿಯಿರಿ. ಹೆಸರು ಕೇಳಿಸಿಕೊಳ್ಳಿ. Frau ಅಥವಾ Herr ಕೇಳಿಸಿಕೊಳ್ಳಿ. Information ಕೇಳಿಸಿಕೊಳ್ಳಿ. ಅಷ್ಟೇ, ಅರ್ಥ ಸುಲಭವಾಗಿ ಗೊತ್ತಾಗುತ್ತದೆ.\r\n\r\nಸ್ವಪರಿಚಯ (Introductions)\r\nನೀವು ಇನ್ಫಾರ್ಮೇಶನ್ ಕೌಂಟರ್ ಹತ್ತಿರಕ್ಕೆ ಹೋಗಿದ್ದೀರಿ. ಅಲ್ಲಿ ನೀವು ನಿಮ್ಮ ಹೆಸರನ್ನು ಹೇಳಬೇಕು. ಜರ್ಮನ್‌ನಲ್ಲಿ ಹೇಗೆ ಹೇಳುತ್ತೀರಿ? Very simple.\r\n\r\nGuten Tag. Mein Name ist Jeremiah.\r\n\r\nಅಂದರೆ: Good day. My name is Jeremiah. (ನಮಸ್ಕಾರ. ನನ್ನ ಹೆಸರು ಜೆರೆಮಿಯಾ.)\r\n\r\nಇಲ್ಲಿ Guten Tag ಅಂದರೆ hello ಅಥವಾ good day. ಫಾರ್ಮಲ್ (formal) ಸಂದರ್ಭಗಳಲ್ಲಿ ಇದು ಬಹಳ ಒಳ್ಳೆಯ phrase.\r\n\r\nMein Name ist... ಅಂದರೆ my name is... (ನನ್ನ ಹೆಸರು...)\r\n\r\nಉದಾಹರಣೆ:\r\n\r\nMein Name ist Peter. (ನನ್ನ ಹೆಸರು ಪೀಟರ್.)\r\n\r\nMein Name ist Meier. (ನನ್ನ ಹೆಸರು ಮೇಯರ್.)\r\n\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ಹೆಸರು ಹೇಳಲು ಇನ್ನೊಂದು common ವಾಕ್ಯ ಇದೆ:\r\n\r\nIch heiße Jeremiah.\r\nಅಂದರೆ: My name is Jeremiah.\r\n\r\nಇದು ಬಿಗಿನರ್‌ಗಳಿಗೆ ಬಹಳ important ವಾಕ್ಯ. Repeat ಮಾಡಿ: Ich heiße Jeremiah.\r\n\r\nಇನ್ನೊಂದು ವಿಧಾನ:\r\n\r\nIch bin Jeremiah.\r\nಅಂದರೆ: I am Jeremiah.\r\n\r\nSo, ಹೆಸರು ಹೇಳಲು ಮೂರು ವಿಧಾನಗಳಿವೆ (Three ways):\r\n\r\nMein Name ist Jeremiah.\r\n\r\nIch heiße Jeremiah.\r\n\r\nIch bin Jeremiah.\r\n\r\nಮೂರು ಸರಿ. ಆದರೆ ಬಿಗಿನರ್ ಲೆವೆಲ್‌ನಲ್ಲಿ Mein Name ist... ಮತ್ತು Ich heiße... ಬಹಳ useful.\r\n\r\nಈಗ ಒಂದು ಸಣ್ಣ ಸೀನ್ (small scene) imagine ಮಾಡಿ:\r\n\r\nReceptionist: Guten Tag.\r\n\r\nYou: Guten Tag. Mein Name ist Jeremiah.\r\n\r\nReceptionist: Heißen Sie Jeremiah Elior?\r\n\r\nYou: Ja, ich bin Jeremiah Elior.\r\n\r\nಇಲ್ಲಿ Ja ಅಂದರೆ yes (ಹೌದು).\r\n\r\nVorname ಮತ್ತು Nachname\r\nVorname ಅಂದರೆ first name (ಮೊದಲ ಹೆಸರು).\r\n\r\nNachname ಅಂದರೆ last name (ಕೊನೆಯ ಹೆಸರು / ಮನೆತನದ ಹೆಸರು).\r\n\r\nಉದಾಹರಣೆ:\r\nJeremiah Elior ಎಂಬ ಹೆಸರು ತೆಗೆದುಕೊಂಡರೆ:\r\n\r\nMein Vorname ist Jeremiah. (ನನ್ನ ಮೊದಲ ಹೆಸರು ಜೆರೆಮಿಯಾ.)\r\n\r\nMein Nachname ist Elior. (ನನ್ನ ಕೊನೆಯ ಹೆಸರು ಎಲಿಯೋರ್.)\r\n\r\nCommon mistake: ಬಹಳಷ್ಟು ಜನರು ಜರ್ಮನ್ ಫಾರ್ಮ್‌ಗಳನ್ನು ತುಂಬುವಾಗ (filling forms) Vorname ಮತ್ತು Nachname ಕನ್ಫ್ಯೂಸ್ ಆಗುತ್ತಾರೆ. ಜರ್ಮನಿಯಲ್ಲಿ ಫಾರ್ಮ್‌ಗಳಲ್ಲಿ ಇವು ಬಹಳ ಕಾಮನ್.\r\n\r\nVorname = first name.\r\n\r\nNachname = family name or last name.\r\nಇದನ್ನು ಚೆನ್ನಾಗಿ ನೆನಪಿಟ್ಟುಕೊಳ್ಳಿ.\r\n\r\nಇತರರ ಹೆಸರನ್ನು ಕೇಳುವುದು (Asking Names)\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ನಯವಾಗಿ (polite way) ಕೇಳುವುದು ಹೇಗೆ:\r\n\r\nWie heißen Sie, bitte?\r\nಅಂದರೆ: What is your name, please? (ದಯವಿಟ್ಟು ನಿಮ್ಮ ಹೆಸರೇನು?)\r\n\r\nಇಲ್ಲಿ Sie ಅಂದರೆ polite you. ಕನ್ನಡದಲ್ಲಿ “ತಾವು” ಅಥವಾ ಮರ್ಯಾದೆಯಿಂದ \"ನೀವು\" ಎಂದಹಾಗೆ.\r\nRepeat: Wie heißen Sie, bitte?\r\n\r\nಉತ್ತರ (Answer):\r\nIch heiße Jeremiah. ಅಥವಾ Mein Name ist Jeremiah.\r\n\r\nಇನ್ನೊಂದು ಪ್ರಶ್ನೆ:\r\n\r\nHeißen Sie Hans Meier? (ನೀವು ಹ್ಯಾನ್ಸ್ ಮೇಯರ್ ಅವರೇ?)\r\n\r\nಉತ್ತರ:\r\nJa, ich bin Hans Meier. (ಹೌದು, ನಾನು ಹ್ಯಾನ್ಸ್ ಮೇಯರ್.)\r\nಅಥವಾ\r\nNein, mein Vorname ist Peter. (ಇಲ್ಲ, ನನ್ನ ಮೊದಲ ಹೆಸರು ಪೀಟರ್.)\r\nಇಲ್ಲಿ Nein ಅಂದರೆ no (ಇಲ್ಲ).\r\n\r\nFormal ಮತ್ತು Informal (Sie vs. du)\r\nಜರ್ಮನ್‌ನಲ್ಲಿ “you” (ನೀವು/ನೀನು) ಗೆ ಎರಡು ಕಾಮನ್ ಫಾರ್ಮ್‌ಗಳಿವೆ: Sie ಮತ್ತು du.\r\n\r\nSie ಅಂದರೆ formal you. ಅಪರಿಚಿತ ದೊಡ್ಡವರು, ಆಫೀಸರ್ಸ್, ಟೀಚರ್ಸ್, ರಿಸೆಪ್ಷನಿಸ್ಟ್, ಡಾಕ್ಟರ್ಸ್, ಮ್ಯಾನೇಜರ್ಸ್, ಮತ್ತು ಆಫೀಶಿಯಲ್ ಜಾಗಗಳಲ್ಲಿ ಇದನ್ನು ಉಪಯೋಗಿಸಬೇಕು (ಮರ್ಯಾದಾ ಸೂಚಕ \"ನೀವು\").\r\n\r\ndu ಅಂದರೆ informal you. ಫ್ರೆಂಡ್ಸ್, ಫ್ಯಾಮಿಲಿ, ಮಕ್ಕಳು, ಹತ್ತಿರದವರ ಜೊತೆ ಉಪಯೋಗಿಸುತ್ತಾರೆ (\"ನೀನು\").\r\n\r\nಉದಾಹರಣೆ:\r\n\r\nFormal: Wie heißen Sie?\r\n\r\nInformal: Wie heißt du?\r\n\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ಗೌರವ (respect) ತೋರಿಸಲು Sie ಬಹಳ useful ಆದ cultural point ಆಗಿದೆ.\r\n\r\nNumbers 1 ರಿಂದ 10 (ಸಂಖ್ಯೆಗಳು)\r\nListen and repeat (ಕೇಳಿ ಮತ್ತು ಪುನರಾವರ್ತಿಸಿ):\r\n\r\neins\r\n\r\nzwei\r\n\r\ndrei\r\n\r\nvier\r\n\r\nfünf\r\n\r\nsechs\r\n\r\nsieben\r\n\r\nacht\r\n\r\nneun\r\n\r\nzehn\r\n\r\nನಂಬರ್ಸ್ ಏಕೆ important? Very simple. ಜರ್ಮನಿಯಲ್ಲಿ ನೀವು ಬಸ್ ನಂಬರ್ ನೋಡಬೇಕು, ಪ್ಲಾಟ್‌ಫಾರ್ಮ್ ನಂಬರ್ ನೋಡಬೇಕು, ಅಪಾಯಿಂಟ್‌ಮೆಂಟ್ ಟೋಕನ್ ನಂಬರ್ ಕೇಳಿಸಿಕೊಳ್ಳಬೇಕು, ಫೋನ್ ನಂಬರ್ ಹೇಳಬೇಕು, ರೂಮ್ ನಂಬರ್ ಹೇಳಬೇಕು.\r\n\r\nಉದಾಹರಣೆ:\r\n\r\nBus 7 = Bus sieben\r\n\r\nRoom 8 = Zimmer acht\r\n\r\nPlatform 3 = Gleis drei\r\n\r\nBeginner mistake (ಉಚ್ಚಾರಣೆ / Pronunciation):\r\n\r\nzwei ಅನ್ನು “ಜ್ವೈ” ಎನ್ನುವ ಬದಲು “ತ್ಸ್ವೈ” (ts-vai) ತರಹ ಉಚ್ಚರಿಸಬೇಕು.\r\n\r\nsieben ಅನ್ನು “ಸೀಬೆನ್” ತರಹ ಉಚ್ಚರಿಸಬೇಕು.\r\n\r\nacht ನಲ್ಲಿ ಸೌಂಡ್ ಸ್ವಲ್ಪ ಸ್ಟ್ರಾಂಗ್. ಇಂಗ್ಲಿಷ್‌ನ “act” ತರಹ ಅಲ್ಲ. ಜರ್ಮನ್ ಸೌಂಡ್ ಸ್ವಲ್ಪ ಗಂಟಲಿನಿಂದ ಬರುತ್ತದೆ.\r\n\r\nDon’t worry. ಮೊದಲ ದಿನವೇ ಪರ್ಫೆಕ್ಟ್ ಉಚ್ಚಾರಣೆ ಅವಶ್ಯಕತೆಯಿಲ್ಲ. ಆದರೆ ಕೇಳುವುದು ಮತ್ತು ರಿಪೀಟ್ ಮಾಡುವುದು ಮುಖ್ಯ.\r\n\r\n\"Wie heißt das auf Deutsch?\" ಮತ್ತು ಶಬ್ದಕೋಶ (Vocabulary)\r\nಭಾಷೆ ಕಲಿಯಲು ಒಂದು ಅತ್ಯದ್ಭುತ (powerful) ವಾಕ್ಯ ಇಲ್ಲಿದೆ:\r\n\r\nWie heißt das auf Deutsch?\r\nಇದರ ಅರ್ಥ: ಇದನ್ನು ಜರ್ಮನ್‌ನಲ್ಲಿ ಏನೆಂದು ಕರೆಯುತ್ತಾರೆ? (What is this called in German?)\r\n\r\nನೀವು ಯಾವುದೇ ವಸ್ತುವನ್ನು ತೋರಿಸಿ ಈ ವಾಕ್ಯವನ್ನು ಕೇಳಬಹುದು.\r\n\r\nಉದಾಹರಣೆ:\r\nಟ್ರೈನ್ ತೋರಿಸಿ ಕೇಳಿದರೆ: Wie heißt das auf Deutsch?\r\nಉತ್ತರ: Das ist der Zug. (ಅಂದರೆ: ಇದು ಟ್ರೈನ್.)\r\n\r\nದೈನಂದಿನ ಪದಗಳು ಮತ್ತು Articles (der, die, das)\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ನಾಮಪದಗಳಿಗೆ (nouns) ಆರ್ಟಿಕಲ್ಸ್ (articles) ಇರುತ್ತವೆ. ಇಂಗ್ಲಿಷ್‌ನಲ್ಲಿ ಕೇವಲ \"the\" ಮಾತ್ರ ಇರುತ್ತದೆ. ಆದರೆ ಜರ್ಮನ್‌ನಲ್ಲಿ ಮೂರು definite articles ಇವೆ:\r\n\r\nder (masculine / ಪುಲ್ಲಿಂಗ)\r\n\r\ndie (feminine / ಸ್ತ್ರೀಲಿಂಗ)\r\n\r\ndas (neuter / ನಪುಂಸಕಲಿಂಗ)\r\n\r\nಬಿಗಿನರ್ ಆಗಿ ನೀವು ಈಗಲೇ ಇದರ ಲಾಜಿಕ್‌ನಲ್ಲಿ ಬೀಳಬೇಡಿ. ಬೆಸ್ಟ್ ಮೆಥಡ್ ಏನೆಂದರೆ, ಪದವನ್ನು ಯಾವಾಗಲೂ ಆರ್ಟಿಕಲ್ ಜೊತೆಯಲ್ಲೇ ಕಲಿಯಿರಿ. (ಉದಾ: ಕೇವಲ Taxi ಎನ್ನುವ ಬದಲು das Taxi ಎಂದು ಕಲಿಯಿರಿ).\r\n\r\nಜರ್ಮನ್ ಪದ (Article ಜೊತೆ)	ಅರ್ಥ (Meaning)\r\nder Zug	ರೈಲು (train)\r\ndas Taxi	ಟ್ಯಾಕ್ಸಿ (taxi)\r\ndas Hotel	ಹೋಟೆಲ್ (hotel)\r\ndie Bank	ಬ್ಯಾಂಕ್ (bank)\r\ndas Telefon	ಟೆಲಿಫೋನ್ (telephone)\r\ndie Zeitung	ನ್ಯೂಸ್‌ಪೇಪರ್ (newspaper)\r\nder Geldautomat	ಎಟಿಎಂ (ATM)\r\nder Bus	ಬಸ್ (bus)\r\ndie Uhr	ಗಡಿಯಾರ (clock / watch)\r\nKnown words (ತಿಳಿದಿರುವ ಪದಗಳು):\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ಕೆಲವು ಪದಗಳು ನಮಗೆ ಈಗಾಗಲೇ familiar ಆಗಿವೆ. Like: Taxi, Hotel, Bank, Telefon, Zoo, Zentrum. ಜರ್ಮನ್ ಸಂಪೂರ್ಣವಾಗಿ ಹೊಸ ಭಾಷೆಯಲ್ಲ, ಇವುಗಳನ್ನು ನೋಡಿದಾಗ ಕಾನ್ಫಿಡೆನ್ಸ್ ಬರುತ್ತದೆ.\r\n\r\nMenschen am Bahnhof (ಸ್ಟೇಷನ್‌ನಲ್ಲಿರುವ ಜನರು)\r\nಪುರುಷ (Male)	ಮಹಿಳೆ (Female)	ಅರ್ಥ (Meaning)\r\nder Reporter	die Reporterin	ರಿಪೋರ್ಟರ್ (reporter)\r\nder Tourist	die Touristin	ಪ್ರವಾಸಿ (tourist)\r\nder Verkäufer	die Verkäuferin	ಮಾರಾಟಗಾರ (salesperson)\r\nಗಮನಿಸಿ: ಜರ್ಮನ್‌ನಲ್ಲಿ ವೃತ್ತಿ ಅಥವಾ ಜನರ ಪದಗಳಲ್ಲಿ ಮಹಿಳೆಯರನ್ನು ಸೂಚಿಸಲು ಸಾಮಾನ್ಯವಾಗಿ ಕೊನೆಯಲ್ಲಿ -in ಸೇರಿಸಲಾಗುತ್ತದೆ.\r\n\r\nಇತರ ಪದಗಳು:\r\n\r\nder Junge = ಹುಡುಗ (boy)\r\n\r\ndas Mädchen = ಹುಡುಗಿ (girl)\r\n\r\ndas Baby = ಮಗು (baby)\r\n\r\ndie Zwillinge = ಅವಳಿ ಮಕ್ಕಳು (twins)\r\n\r\nಚಿಕ್ಕ ಸಂಭಾಷಣೆಗಳು (Small Dialogues) ಮತ್ತು ಶುಭಾಶಯಗಳು\r\nGuten Tag, Frau Soprana. Herzlich willkommen. (ಶುಭ ದಿನ, ಶ್ರೀಮತಿ ಸೊಪ್ರಾನ. ಆತ್ಮೀಯ ಸ್ವಾಗತ.)\r\n\r\nDanke für die Blumen. (ಹೂವುಗಳಿಗಾಗಿ ಧನ್ಯವಾದಗಳು.)\r\n\r\nAuf Wiedersehen. Gute Reise. (ವಿದಾಯ. ಪ್ರಯಾಣ ಸುಖಕರವಾಗಿರಲಿ / Have a good journey.)\r\n\r\nOh! Verzeihung! (ಓಹ್! ಕ್ಷಮಿಸಿ / Sorry.)\r\n\r\nAuf Wiedersehen ಫಾರ್ಮಲ್ ಗುಡ್‌ಬೈ.\r\n\r\nTschüs ಕ್ಯಾಶುಯಲ್ (casual) ಗುಡ್‌ಬೈ.\r\n\r\nVerzeihung ಅಂದರೆ ಕ್ಷಮಿಸಿ (sorry/excuse me).\r\n\r\nSingular ಮತ್ತು Plural (ಏಕವಚನ ಮತ್ತು ಬಹುವಚನ)\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ಬಹುವಚನ (plural) ರೂಪಗಳು ವಿಭಿನ್ನವಾಗಿರುತ್ತವೆ. ಇಂಗ್ಲಿಷ್‌ನಂತೆ ಯಾವಾಗಲೂ ಕೊನೆಗೆ “s” ಸೇರಿಸುವುದಿಲ್ಲ.\r\n\r\nImportant beginner rule: Plural nouns ಗಳಿಗೆ ಸಾಮಾನ್ಯವಾಗಿ die ಆರ್ಟಿಕಲ್ ಉಪಯೋಗಿಸಲಾಗುತ್ತದೆ. (Singular ನಲ್ಲಿ der, die, das ಬರಬಹುದು, ಆದರೆ Plural ನಲ್ಲಿ ಸಾಮಾನ್ಯವಾಗಿ die).\r\n\r\nಉದಾಹರಣೆಗಳು:\r\n\r\ndas Telefon ➡️ die Telefone (ಟೆಲಿಫೋನ್‌ಗಳು)\r\n\r\ndas Taxi ➡️ die Taxis (ಟ್ಯಾಕ್ಸಿಗಳು)\r\n\r\ndas Hotel ➡️ die Hotels (ಹೋಟೆಲ್‌ಗಳು)\r\n\r\nder Geldautomat ➡️ die Geldautomaten (ಎಟಿಎಂಗಳು)\r\n\r\ndie Blume ➡️ die Blumen (ಹೂವುಗಳು)\r\n\r\nCommon mistake: das Taxis ಎಂದು ಹೇಳುವುದು ತಪ್ಪು. Correct: die Taxis.\r\n\r\nChapter Summary (ಸಾರಾಂಶ)\r\nಜರ್ಮನ್ ಕಲಿಯುವುದು ಒಂದು ಟ್ರೈನ್ ಜರ್ನಿ (train journey) ಹಾಗೆ.\r\n\r\nಮೊದಲ ಸ್ಟೇಷನ್: greetings.\r\n\r\nಎರಡನೇ ಸ್ಟೇಷನ್: name introduction.\r\n\r\nಮೂರನೇ ಸ್ಟೇಷನ್: numbers.\r\n\r\nನಾಲ್ಕನೇ ಸ್ಟೇಷನ್: daily words.\r\n\r\nಐದನೇ ಸ್ಟೇಷನ್: articles.\r\n\r\nಆರನೇ ಸ್ಟೇಷನ್: singular and plural.\r\n\r\nನೀವು ಒಮ್ಮೆಲೇ ಫೈನಲ್ ಡೆಸ್ಟಿನೇಶನ್‌ಗೆ ಹೋಗಲು ಸಾಧ್ಯವಿಲ್ಲ. ಪ್ರತಿಯೊಂದು ಸ್ಟೇಷನ್ ದಾಟಬೇಕು. ಈ ಬೇಸಿಕ್ಸ್ ಅನ್ನು ಸ್ಟ್ರಾಂಗ್ ಆಗಿ ಕಲಿತರೆ ಮುಂದಿನ ಜರ್ಮನ್ ಜರ್ನಿ ಈಸಿ ಆಗುತ್ತದೆ.\r\n\r\nQuick Quiz (ರಸಪ್ರಶ್ನೆ)\r\nGuten Tag ಅಂದರೆ ಏನು?\r\n\r\nMein Name ist Jeremiah ಅಂದರೆ ಏನು?\r\n\r\nಜರ್ಮನ್‌ನಲ್ಲಿ ಮರ್ಯಾದೆಯಿಂದ (polite ಆಗಿ) “ನಿಮ್ಮ ಹೆಸರೇನು?” ಎಂದು ಹೇಗೆ ಕೇಳುತ್ತಾರೆ?\r\n\r\nFrau ಮತ್ತು Herr ಅರ್ಥವೇನು?\r\n\r\nಜರ್ಮನ್ ನಂಬರ್ಸ್ 1 ರಿಂದ 5 ಹೇಳಿ.\r\n\r\nWie heißt das auf Deutsch? ಇದರ ಅರ್ಥವೇನು?\r\n\r\nCorrect article ಯಾವುದು: Taxi ಗೆ der, die, ಅಥವಾ das?\r\n\r\nder Zug ಅಂದರೆ ಏನು?\r\n\r\ndas Hotel ನ plural (ಬಹುವಚನ) ಏನು?\r\n\r\nಅಪರಿಚಿತ ದೊಡ್ಡವರೊಂದಿಗೆ ಮಾತನಾಡುವಾಗ du ಬಳಸಬೇಕಾ, Sie ಬಳಸಬೇಕಾ?\r\n\r\nಉತ್ತರಗಳು (Answers):\r\n\r\nGood day ಅಥವಾ hello.\r\n\r\nMy name is Jeremiah. (ನನ್ನ ಹೆಸರು ಜೆರೆಮಿಯಾ).\r\n\r\nWie heißen Sie, bitte?\r\n\r\nFrau ಅಂದರೆ Mrs. ಅಥವಾ Ms. Herr ಅಂದರೆ Mr.\r\n\r\neins, zwei, drei, vier, fünf.\r\n\r\nಇದನ್ನು ಜರ್ಮನ್‌ನಲ್ಲಿ ಏನೆಂದು ಕರೆಯುತ್ತಾರೆ? (What is this called in German?)\r\n\r\ndas Taxi.\r\n\r\nಟ್ರೈನ್ (the train).\r\n\r\ndie Hotels.\r\n\r\nSie.\r\n\r\nOutro:\r\nಸ್ನೇಹಿತರೆ, ಇದೇ ನಮ್ಮ ಮೊದಲ German Kannada ಪಾಡ್‌ಕಾಸ್ಟ್ ಲೆಸನ್. ಈ ಲೆಸನ್ ಅನ್ನು ಒಮ್ಮೆ ಕೇಳಿದರೆ ಸಾಲದು. ದಿನವೂ 2 ಅಥವಾ 3 ಬಾರಿ ರಿಪೀಟ್ ಮಾಡಿ. ವಿಶೇಷವಾಗಿ ವಾಕ್ಯಗಳನ್ನು (sentences) ರಿಪೀಟ್ ಮಾಡಿ.\r\nಭಾಷೆಯು ಮಾತನಾಡುವುದರ ಮೂಲಕ ಬರುತ್ತದೆ. ಆದ್ದರಿಂದ ಕೇಳಿ, ರಿಪೀಟ್ ಮಾಡಿ, ಚಿಕ್ಕ ವಾಕ್ಯಗಳನ್ನು ದಿನನಿತ್ಯದ ಜೀವನದಲ್ಲಿ ಉಪಯೋಗಿಸಿ.\r\n\r\nDanke schön. Auf Wiedersehen. (ತುಂಬಾ ಧನ್ಯವಾದಗಳು. ವಿದಾಯ.)', 'https://silver-llama-257051.hostingersite.com/uploads/audio/1782405644-------------------_------------------------------_------------------_---------_------------------_--------------_chapter1.m4a', 1, '2026-06-25 16:40:44', '2026-06-25 16:40:44');

